import React, { useState } from 'react';
import { Outlet, Navigate, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogOut, Users, FileText, UserCircle, KeyRound, X, Loader2, Briefcase, Activity } from 'lucide-react';

const AdminLayout = () => {
    const { user, login } = useAuth(); // Need login to update context if needed, but not strictly required
    const navigate = useNavigate();
    const location = useLocation();

    const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
    const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false);

    // Profile States
    const [fullName, setFullName] = useState(user?.full_name || '');
    const [email, setEmail] = useState(user?.email || '');
    const [department, setDepartment] = useState(user?.department || '');
    const [position, setPosition] = useState(user?.position || '');
    const [avatarB64, setAvatarB64] = useState(user?.avatar_b64 || '');
    const [profileError, setProfileError] = useState('');
    const [profileLoading, setProfileLoading] = useState(false);
    const [profileSuccess, setProfileSuccess] = useState(false);

    // Password States
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [passwordError, setPasswordError] = useState('');
    const [passwordLoading, setPasswordLoading] = useState(false);
    const [passwordSuccess, setPasswordSuccess] = useState(false);

    if (!user) {
        return <Navigate to="/admin/login" replace />;
    }

    const navItems = [
        { label: '職缺管理', path: '/admin/jobs', icon: <Briefcase size={20} /> },
        { label: '履歷管理', path: '/admin/resumes', icon: <FileText size={20} /> },
        { label: '甄試', path: '/admin/dashboard', icon: <Activity size={20} /> },
        {
            label: '設定',
            icon: <KeyRound size={20} />, /* temporary icon */
            children: [
                ...(user.role === 'admin' || user.role === 'superadmin' ? [
                    { label: '系統權限管理', path: '/admin/users' },
                    { label: '系統操作日誌', path: '/admin/audit-logs' }
                ] : []),
                { label: '管理個人資訊', action: () => setIsProfileModalOpen(true) }
            ]
        }
    ];

    const [activeDropdown, setActiveDropdown] = useState(null);

    const handleAvatarUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            if (file.size > 2 * 1024 * 1024) {
                setProfileError('照片大小不可超過 2MB');
                return;
            }
            const reader = new FileReader();
            reader.onloadend = () => {
                setAvatarB64(reader.result);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleUpdateProfile = async (e) => {
        e.preventDefault();
        setProfileError('');
        setProfileSuccess(false);
        setProfileLoading(true);

        try {
            const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001/api/v1';
            const response = await fetch(`${apiUrl}/admin/me/profile`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('adminToken')}`
                },
                body: JSON.stringify({ full_name: fullName, email, department, position, avatar_b64: avatarB64 })
            });

            const data = await response.json();
            if (!response.ok) throw new Error(data.error || '個人資訊更新失敗');

            setProfileSuccess(true);

            // Update AuthContext cache
            if (login.name !== 'login') {
                // If using context that supports partial updates (updateUserContext)
                // we simulate it if we don't have direct access yet. But we know we added updateUserContext.
            }
            // For now, emit a custom event or force window reload if context update is tricky. Let's try updating context if we exposed it, otherwise reload
            const updatedUser = { ...user, full_name: fullName, email, department, position, avatar_b64: avatarB64 };
            localStorage.setItem('adminUser', JSON.stringify(updatedUser)); // manual persist

            setTimeout(() => {
                setIsProfileModalOpen(false);
                setProfileSuccess(false);
                window.location.reload(); // Quick sync
            }, 1000);

        } catch (err) {
            setProfileError(err.message);
        } finally {
            setProfileLoading(false);
        }
    };

    const handleUpdatePassword = async (e) => {
        e.preventDefault();
        setPasswordError('');
        setPasswordSuccess(false);

        if (newPassword !== confirmPassword) return setPasswordError('兩次輸入的新密碼不一致');
        if (newPassword.length < 6) return setPasswordError('新密碼長度必須至少 6 個字元');
        if (!currentPassword) return setPasswordError('請輸入目前密碼');

        setPasswordLoading(true);
        try {
            const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001/api/v1';
            const response = await fetch(`${apiUrl}/admin/me/password`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('adminToken')}`
                },
                body: JSON.stringify({ currentPassword, newPassword })
            });

            const data = await response.json();
            if (!response.ok) throw new Error(data.error || '密碼更新失敗');

            setPasswordSuccess(true);
            setCurrentPassword('');
            setNewPassword('');
            setConfirmPassword('');

            setTimeout(() => {
                setIsPasswordModalOpen(false);
                setPasswordSuccess(false);
            }, 2000);

        } catch (err) {
            setPasswordError(err.message === 'Incorrect current password' ? '目前密碼輸入錯誤' : err.message);
        } finally {
            setPasswordLoading(false);
        }
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', width: '100vw', background: 'var(--bg-main)', overflow: 'hidden' }}>
            {/* Tech Aesthetic Top Navigation Bar */}
            <header style={{
                width: '100%',
                background: 'var(--bg-card)',
                color: 'var(--color-structural)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                borderBottom: '2px solid var(--border-structural)',
                boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
                zIndex: 10,
                padding: '0 2rem',
                minHeight: '70px'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '2rem' }}>
                    {/* Brand Logo */}
                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '0.8rem' }}>
                        <h2 style={{ fontFamily: 'var(--font-heading)', fontSize: '1.5rem', fontWeight: '700', margin: 0, letterSpacing: '0.1em', color: 'var(--color-primary)' }}>DIANBOPOPO</h2>
                        <span style={{ fontFamily: 'var(--font-tech)', fontSize: '0.8rem', opacity: 0.6, letterSpacing: '0.1em' }}>系統管理中心</span>
                    </div>

                    {/* Navigation Menu (Dropdown Logic) */}
                    <nav style={{ display: 'flex', gap: '0.5rem', height: '100%' }}>
                        {navItems.map((item, index) => {
                            const isPathActive = item.path && location.pathname.startsWith(item.path);
                            const isDropdownActive = item.children && item.children.some(child => child.path && location.pathname.startsWith(child.path));
                            const isActive = isPathActive || isDropdownActive;

                            const hasChildren = item.children && item.children.length > 0;

                            return (
                                <div
                                    key={index}
                                    style={{ position: 'relative', height: '100%', display: 'flex' }}
                                    onMouseEnter={() => hasChildren && setActiveDropdown(index)}
                                    onMouseLeave={() => hasChildren && setActiveDropdown(null)}
                                >
                                    <button
                                        onClick={() => {
                                            if (item.path) navigate(item.path);
                                            if (item.action) item.action();
                                        }}
                                        style={{
                                            display: 'flex', alignItems: 'center', gap: '8px', padding: '0 1.2rem',
                                            background: isActive ? 'rgba(228, 179, 89, 0.1)' : 'transparent',
                                            color: isActive ? 'var(--color-primary)' : 'rgba(45,34,28,0.7)',
                                            border: 'none',
                                            borderBottom: isActive ? '3px solid var(--color-primary)' : '3px solid transparent',
                                            cursor: 'pointer',
                                            transition: 'all 0.2s',
                                            fontWeight: isActive ? '700' : '500',
                                            fontFamily: 'var(--font-body)',
                                            height: '70px'
                                        }}
                                        onMouseEnter={e => { if (!isActive) e.currentTarget.style.color = 'var(--color-primary)' }}
                                        onMouseLeave={e => { if (!isActive) e.currentTarget.style.color = 'rgba(45,34,28,0.7)' }}
                                    >
                                        {/* {item.icon} */} {/* Remove icons to make it cleaner, or keep? The user wants clean, let's omit icons for top level except for maybe hover effect */}
                                        {item.label}
                                    </button>

                                    {/* Dropdown Menu */}
                                    {hasChildren && activeDropdown === index && (
                                        <div style={{
                                            position: 'absolute',
                                            top: '70px',
                                            left: '50%',
                                            transform: 'translateX(-50%)',
                                            background: 'white',
                                            minWidth: '200px',
                                            boxShadow: '0 8px 24px rgba(45, 34, 28, 0.12)',
                                            borderRadius: '0 0 8px 8px',
                                            border: '1px solid var(--border-structural)',
                                            borderTop: 'none', // seamlessly attached to header
                                            overflow: 'hidden',
                                            display: 'flex',
                                            flexDirection: 'column',
                                            zIndex: 100,
                                            animation: 'fadeInDown 0.2s ease-out'
                                        }}>
                                            {item.children.map((child, cIndex) => (
                                                <button
                                                    key={cIndex}
                                                    onClick={() => {
                                                        setActiveDropdown(null);
                                                        if (child.path) navigate(child.path);
                                                        if (child.action) child.action();
                                                    }}
                                                    style={{
                                                        padding: '1rem 1.5rem',
                                                        border: 'none',
                                                        background: 'transparent',
                                                        textAlign: 'left',
                                                        fontSize: '0.95rem',
                                                        color: 'var(--color-structural)',
                                                        cursor: 'pointer',
                                                        transition: 'background 0.2s, color 0.2s',
                                                        borderBottom: cIndex < item.children.length - 1 ? '1px solid rgba(45,34,28,0.05)' : 'none',
                                                        fontFamily: 'var(--font-body)',
                                                        letterSpacing: '0.05em'
                                                    }}
                                                    onMouseEnter={e => { e.currentTarget.style.background = 'rgba(228, 179, 89, 0.05)'; e.currentTarget.style.color = 'var(--color-primary)'; }}
                                                    onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--color-structural)'; }}
                                                >
                                                    {child.label}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )
                        })}
                    </nav>
                </div>

                {/* Right Side Actions */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>

                    {/* User Profile Mini */}
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', paddingRight: '1rem', borderRight: '2px solid rgba(45,34,28,0.1)' }}>
                        <div style={{ textAlign: 'right' }}>
                            <div style={{ fontSize: '0.9rem', fontWeight: 'bold', fontFamily: 'var(--font-heading)', color: 'var(--color-structural)' }}>
                                {user.full_name || user.username}
                            </div>
                            <div style={{ fontSize: '0.7rem', fontFamily: 'var(--font-tech)', color: 'var(--color-primary)', opacity: 0.8 }}>
                                {user.department ? `${user.department} - ${user.position}` : `ROLE: ${user.role}`}
                            </div>
                        </div>
                        <div style={{ background: 'var(--color-primary)', borderRadius: '50%', width: '36px', height: '36px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, overflow: 'hidden' }}>
                            {user.avatar_b64 ? (
                                <img src={user.avatar_b64} alt="Avatar" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            ) : (
                                <UserCircle size={24} color="var(--bg-main)" />
                            )}
                        </div>
                    </div>

                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                        {/* Replaced standalone profile/password edit icons with dropdown menu access */}

                        <button
                            onClick={() => {
                                localStorage.removeItem('adminToken');
                                localStorage.removeItem('adminUser');
                                navigate('/admin/login');
                                window.location.reload();
                            }}
                            title="登出系統"
                            style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-error)', padding: '8px', borderRadius: '4px', transition: 'all 0.2s', opacity: 0.8 }}
                            onMouseEnter={e => { e.currentTarget.style.background = 'rgba(224, 49, 49, 0.1)'; e.currentTarget.style.opacity = 1; }}
                            onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.opacity = 0.8; }}
                        ><LogOut size={20} /></button>
                    </div>
                </div>
            </header>

            {/* Main Content Area */}
            <main style={{ flex: 1, overflowY: 'auto', background: 'transparent', position: 'relative' }}>
                <Outlet />
            </main>

            {/* Managed Profile Modal */}
            {isProfileModalOpen && (
                <div className="profile-modal-overlay">
                    <div className="profile-modal-content" style={{ position: 'relative', background: 'var(--bg-main)', borderRadius: '0px', padding: '3rem' }}>
                        <button
                            onClick={() => {
                                setIsProfileModalOpen(false);
                                setProfileError('');
                                setProfileSuccess(false);
                            }}
                            style={{ position: 'absolute', top: '1.5rem', right: '1.5rem', background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-structural)' }}
                        >
                            <X size={24} />
                        </button>

                        <h3 className="step-title" style={{ fontSize: '1.8rem', marginTop: 0 }}>個人資訊管理</h3>
                        <p className="step-desc" style={{ marginBottom: '2rem' }}>更換帳號 [{user.username}] 的基本資料與登入密碼</p>

                        {profileSuccess ? (
                            <div style={{ background: 'rgba(16, 185, 129, 0.1)', border: '1px solid #10b981', color: '#047857', padding: '1rem', marginBottom: '1.5rem', fontFamily: 'var(--font-tech)', fontSize: '0.9rem', textAlign: 'center' }}>
                                更新成功！視窗將自動關閉
                            </div>
                        ) : (
                            <form onSubmit={handleUpdateProfile}>
                                {profileError && (
                                    <div style={{ background: 'rgba(224, 49, 49, 0.1)', border: '1px solid var(--color-error)', color: 'var(--color-error)', padding: '1rem', marginBottom: '1.5rem', fontFamily: 'var(--font-tech)', fontSize: '0.9rem', textAlign: 'center' }}>
                                        [ERROR] {profileError}
                                    </div>
                                )}

                                <div style={{ display: 'flex', gap: '1.5rem', marginBottom: '2rem' }}>
                                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1rem', flexShrink: 0 }}>
                                        <div style={{ width: '100px', height: '100px', border: '1px dashed var(--border-structural)', borderRadius: '4px', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.02)' }}>
                                            {avatarB64 ? <img src={avatarB64} alt="Preview" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <UserCircle size={40} opacity={0.3} />}
                                        </div>
                                        <label style={{ background: 'var(--color-structural)', color: 'white', padding: '0.4rem 0.8rem', fontSize: '0.8rem', cursor: 'pointer', borderRadius: '4px' }}>
                                            上傳頭像
                                            <input type="file" accept="image/jpeg, image/png" onChange={handleAvatarUpload} style={{ display: 'none' }} />
                                        </label>
                                    </div>
                                    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                        <div className="form-group">
                                            <label className="form-label">顯示名稱 (Full Name)</label>
                                            <input type="text" className="form-input" value={fullName} onChange={e => setFullName(e.target.value)} placeholder="例如：王小明" />
                                        </div>
                                        <div className="form-group">
                                            <label className="form-label">聯絡信箱 (Email)</label>
                                            <input type="email" className="form-input" value={email} onChange={e => setEmail(e.target.value)} placeholder="example@dianbopopo.com" />
                                        </div>
                                    </div>
                                </div>

                                <div className="grid-2" style={{ gap: '1.5rem', marginBottom: '2rem' }}>
                                    <div className="form-group">
                                        <label className="form-label">所屬部門</label>
                                        <input type="text" className="form-input" value={department} onChange={e => setDepartment(e.target.value)} placeholder="例如：人資部" />
                                    </div>
                                    <div className="form-group">
                                        <label className="form-label">職位抬頭</label>
                                        <input type="text" className="form-input" value={position} onChange={e => setPosition(e.target.value)} placeholder="例如：招募專員" />
                                    </div>
                                </div>

                                <div style={{ display: 'flex', gap: '1rem', justifyContent: 'space-between', borderTop: '1px solid var(--border-structural)', paddingTop: '1.5rem' }}>
                                    <button type="button" className="btn-secondary" onClick={() => { setIsProfileModalOpen(false); setIsPasswordModalOpen(true); }} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', background: 'rgba(45,34,28,0.05)', color: 'var(--color-structural)' }}>
                                        <KeyRound size={16} /> 變更登入密碼
                                    </button>
                                    <div style={{ display: 'flex', gap: '1rem' }}>
                                        <button type="button" className="btn-secondary" onClick={() => setIsProfileModalOpen(false)}>取消</button>
                                        <button type="submit" className="btn-wizard-next" disabled={profileLoading} style={{ padding: '0.8rem 1.5rem', margin: 0, width: 'auto' }}>
                                            {profileLoading ? <Loader2 size={18} className="animate-spin" /> : '儲存變更'}
                                        </button>
                                    </div>
                                </div>
                            </form>
                        )}
                    </div>
                </div>
            )
            }

            {/* Managed Password Modal */}
            {
                isPasswordModalOpen && (
                    <div className="profile-modal-overlay">
                        <div className="profile-modal-content" style={{ position: 'relative', background: 'var(--bg-main)', borderRadius: '0px', padding: '3rem' }}>
                            <button
                                onClick={() => {
                                    setIsPasswordModalOpen(false);
                                    setPasswordError('');
                                    setPasswordSuccess(false);
                                }}
                                style={{ position: 'absolute', top: '1.5rem', right: '1.5rem', background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-structural)' }}
                            >
                                <X size={24} />
                            </button>

                            <h3 className="step-title" style={{ fontSize: '1.8rem', marginTop: 0 }}>變更登入密碼</h3>
                            <p className="step-desc" style={{ marginBottom: '2rem' }}>變更帳號 [{user.username}] 的系統密碼</p>

                            {passwordSuccess ? (
                                <div style={{ background: 'rgba(16, 185, 129, 0.1)', border: '1px solid #10b981', color: '#047857', padding: '1rem', marginBottom: '1.5rem', fontFamily: 'var(--font-tech)', fontSize: '0.9rem', textAlign: 'center' }}>
                                    密碼更新成功！視窗將自動關閉
                                </div>
                            ) : (
                                <form onSubmit={handleUpdatePassword}>
                                    {passwordError && (
                                        <div style={{ background: 'rgba(224, 49, 49, 0.1)', border: '1px solid var(--color-error)', color: 'var(--color-error)', padding: '1rem', marginBottom: '1.5rem', fontFamily: 'var(--font-tech)', fontSize: '0.9rem', textAlign: 'center' }}>
                                            [ERROR] {passwordError}
                                        </div>
                                    )}

                                    <div className="form-group" style={{ marginBottom: '1.2rem' }}>
                                        <label className="form-label">目前密碼</label>
                                        <input
                                            type="password" className="form-input"
                                            value={currentPassword} onChange={e => setCurrentPassword(e.target.value)} required
                                        />
                                    </div>
                                    <div className="form-group" style={{ marginBottom: '1.2rem' }}>
                                        <label className="form-label">新密碼 (至少 6 個字元)</label>
                                        <input
                                            type="password" className="form-input"
                                            value={newPassword} onChange={e => setNewPassword(e.target.value)} required
                                        />
                                    </div>
                                    <div className="form-group" style={{ marginBottom: '2rem' }}>
                                        <label className="form-label">確認新密碼</label>
                                        <input
                                            type="password" className="form-input"
                                            value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required
                                        />
                                    </div>

                                    <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', borderTop: '1px solid var(--border-structural)', paddingTop: '1.5rem' }}>
                                        <button type="button" className="btn-secondary" onClick={() => setIsPasswordModalOpen(false)}>取消</button>
                                        <button type="submit" className="btn-wizard-next" disabled={passwordLoading} style={{ padding: '0.8rem 1.5rem', margin: 0, width: 'auto' }}>
                                            {passwordLoading ? <Loader2 size={18} className="animate-spin" /> : '更新密碼'}
                                        </button>
                                    </div>
                                </form>
                            )}
                        </div>
                    </div>
                )
            }
        </div >
    );
};

export default AdminLayout;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const Mascot = ({ step }) => {
    const [isHovered, setIsHovered] = useState(false);

    // Determine message based on step
    const getMessage = (currentStep) => {
        switch (currentStep) {
            case 1:
                return "歡迎你！好的開始是成功的一半喔！\n(滑過我查看提示)";
            case 2:
                return "哇！好多精彩的經歷，繼續保持！";
            case 3:
                return "讓我知道你的專業跟離職原因吧，我會保密的🤫";
            case 4:
                return "最後一步了！勇敢寫下你的夢想吧✨！";
            default:
                return "加油加油！";
        }
    };

    const message = getMessage(step);

    return (
        <motion.div
            className="mascot-container interactive"
            initial={{ y: 50, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ type: "spring", bounce: 0.5, duration: 0.8 }}
        >
            <AnimatePresence mode="wait">
                {isHovered && (
                    <motion.div
                        key={step}
                        className="mascot-bubble"
                        initial={{ opacity: 0, scale: 0.8, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.8, y: 10 }}
                        transition={{ duration: 0.2 }}
                    >
                        {message}
                        <div className="mascot-bubble-tail"></div>
                    </motion.div>
                )}
            </AnimatePresence>

            <motion.div
                className="mascot-avatar"
                onHoverStart={() => setIsHovered(true)}
                onHoverEnd={() => setIsHovered(false)}
                animate={{
                    y: [0, -10, 0],
                    rotate: [0, 5, -5, 0]
                }}
                transition={{
                    duration: 4,
                    repeat: Infinity,
                    ease: "easeInOut"
                }}
            >
                <img src="/mascot.png?v=3" alt="Mascot" style={{ width: '130px', filter: 'drop-shadow(0 4px 12px rgba(0,0,0,0.15))' }} />
            </motion.div>
        </motion.div>
    );
};

export default Mascot;

