}, {});

// ─── Status Badge ──────────────────────────────────────────────────────────────
const STATUS_COLORS = {
    '待處理': { bg: '#fff7ed', color: '#c2410c', border: '#fed7aa' },
    '初篩合格': { bg: '#f0fdf4', color: '#15803d', border: '#bbf7d0' },
    '待面試': { bg: '#eff6ff', color: '#1d4ed8', border: '#bfdbfe' },
    '核定中': { bg: '#fdf4ff', color: '#7e22ce', border: '#e9d5ff' },
    '即將到職': { bg: '#f0fdf4', color: '#166534', border: '#86efac' },
    '錄用': { bg: '#f0fdf4', color: '#15803d', border: '#6ee7b7' },
};
const StatusBadge = ({ status }) => {
    const s = STATUS_COLORS[status] || { bg: 'rgba(24,24,27,0.06)', color: 'rgba(24,24,27,0.6)', border: 'rgba(24,24,27,0.15)' };
    return (
        <span style={{ padding: '0.45rem 1.1rem', borderRadius: '20px', fontWeight: 'bold', fontSize: '0.9rem', background: s.bg, color: s.color, border: `1px solid ${s.border}`, fontFamily: 'var(--font-tech)', letterSpacing: '0.5px' }}>
            {status || '待處理'}
        </span>
    );
};

// ─── Markdown styling props ────────────────────────────────────────────────────
const MD_COMPONENTS = {
    h1: ({ ...props }) => <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', margin: '0 0 0.8em', borderBottom: '3px solid var(--color-primary)', paddingBottom: '0.3em', color: 'var(--color-structural)' }} {...props} />,
    h2: ({ ...props }) => <h2 style={{ fontSize: '1.15rem', fontWeight: 'bold', margin: '1.8em 0 0.6em', color: 'var(--color-structural)', paddingBottom: '4px', borderBottom: '1px solid rgba(228,179,89,0.3)' }} {...props} />,
    h3: ({ ...props }) => <h3 style={{ fontSize: '1rem', fontWeight: 'bold', margin: '1.2em 0 0.4em', color: 'rgba(45,34,28,0.8)' }} {...props} />,
    p: ({ ...props }) => <p style={{ marginBottom: '0.8em', lineHeight: '1.9' }} {...props} />,
    ul: ({ ...props }) => <ul style={{ listStyleType: 'disc', paddingLeft: '1.4em', marginBottom: '0.8em' }} {...props} />,
    ol: ({ ...props }) => <ol style={{ listStyleType: 'decimal', paddingLeft: '1.4em', marginBottom: '0.8em' }} {...props} />,
    li: ({ ...props }) => <li style={{ marginBottom: '0.4em', lineHeight: '1.8' }} {...props} />,
    strong: ({ ...props }) => <strong style={{ color: 'var(--color-primary)', fontWeight: '700' }} {...props} />,
    hr: ({ ...props }) => <hr style={{ border: 'none', borderTop: '1px dashed rgba(228,179,89,0.4)', margin: '1.2em 0' }} {...props} />,
    blockquote: ({ ...props }) => <blockquote style={{ borderLeft: '4px solid var(--color-primary)', margin: '0.8em 0', background: 'rgba(228,179,89,0.06)', padding: '0.6em 1em', color: 'rgba(45,34,28,0.8)', borderRadius: '0 4px 4px 0' }} {...props} />,
    table: ({ ...props }) => <div style={{ overflowX: 'auto', marginBottom: '1.2em' }}><table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.92rem' }} {...props} /></div>,
    thead: ({ ...props }) => <thead style={{ background: 'rgba(45,34,28,0.05)' }} {...props} />,
    th: ({ ...props }) => <th style={{ padding: '0.6em 0.9em', textAlign: 'left', borderBottom: '2px solid var(--color-primary)', fontWeight: '700', color: 'var(--color-structural)', fontSize: '0.8rem' }} {...props} />,
    td: ({ ...props }) => <td style={{ padding: '0.6em 0.9em', borderBottom: '1px solid rgba(45,34,28,0.08)', verticalAlign: 'top', lineHeight: '1.7' }} {...props} />,
    code: ({ inline, ...props }) => inline
        ? <code style={{ background: 'rgba(45,34,28,0.06)', padding: '0.1em 0.35em', borderRadius: '3px', fontFamily: 'var(--font-tech)', fontSize: '0.85em' }} {...props} />
        : <pre style={{ background: 'rgba(45,34,28,0.05)', padding: '1em', overflowX: 'auto', borderRadius: '4px', marginBottom: '1em' }}><code style={{ fontFamily: 'var(--font-tech)', fontSize: '0.85em' }} {...props} /></pre>,
};

// ─── Main Component ────────────────────────────────────────────────────────────
const CandidateDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user } = useAuth();

    const [data, setData] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [aiGenerating, setAiGenerating] = useState(false);
    const [activeTab, setActiveTab] = useState('candidate'); // 'candidate' | 'hr'

    const [newComment, setNewComment] = useState('');
    const [commenting, setCommenting] = useState(false);
    const [uploadState, setUploadState] = useState({ loading: false, error: '', success: '' });

    const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001/api/v1';
    const authHeaders = { 'Authorization': `Bearer ${localStorage.getItem('adminToken')}` };

    const fetchData = async () => {
        try {
            const response = await fetch(`${apiUrl}/admin/candidates/${id}`, { headers: authHeaders });
            if (!response.ok) throw new Error('Failed to fetch candidate details');
            const result = await response.json();
            setData(result);
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchData(); }, [id]);

    const handleResumeUpload = async (file) => {
        if (!file) return;
        setUploadState({ loading: true, error: '', success: '' });
        const formData = new FormData();
        formData.append('resume', file);
        try {
            const res = await fetch(`${apiUrl}/admin/candidates/${id}/resume-upload`, {
                method: 'POST', headers: authHeaders, body: formData
            });
            const json = await res.json();
            if (!res.ok) throw new Error(json.error || '上傳失敗');
            setUploadState({ loading: false, error: '', success: `✅ 已成功解析 ${json.length?.toLocaleString()} 字的履歷內容` });
            fetchData();
        } catch (err) {
            setUploadState({ loading: false, error: err.message, success: '' });
        }
    };

    const handleAddEvaluation = async () => {
        if (!newComment.trim()) return;
        setCommenting(true);
        try {
            const res = await fetch(`${apiUrl}/admin/candidates/${id}/evaluations`, {
                method: 'POST',
                headers: { ...authHeaders, 'Content-Type': 'application/json' },
                body: JSON.stringify({ comments: newComment })
            });
            if (!res.ok) throw new Error('Failed to add evaluation');
            setNewComment('');
            fetchData();
        } catch (err) { alert(err.message); }
        finally { setCommenting(false); }
    };

    const handleRegenerateAi = async () => {
        if (!window.confirm('確定要重新產生 AI 評估報告嗎？約需 30~60 秒。')) return;
        setAiGenerating(true);
        try {
            const res = await fetch(`${apiUrl}/admin/candidates/${id}/analyze`, {
                method: 'POST', headers: authHeaders
            });
            if (!res.ok) { const e = await res.json(); throw new Error(e.error || 'Failed'); }
            await fetchData();
        } catch (err) { alert('錯誤: ' + err.message); }
        finally { setAiGenerating(false); }
    };

    const handleDeleteResume = async () => {
        if (!window.confirm('確定要刪除這份外部履歷嗎？刪除後 AI 再次分析將不含此份履歷內容。')) return;
        try {
            const res = await fetch(`${apiUrl}/admin/candidates/${id}/resume`, {
                method: 'DELETE', headers: authHeaders
            });
            if (!res.ok) { const e = await res.json(); throw new Error(e.error || '刪除失敗'); }
            fetchData();
        } catch (err) { alert('錯誤: ' + err.message); }
    };

    const handlePrint = () => {
        if (!data) return;
        const { candidate, answers, personality, aiReport, workExperiences } = data;

        const workExpHtml = (workExperiences || []).length > 0
            ? workExperiences.map((exp, i) => `<div style="margin-bottom:1em;padding:0.8em;border-left:4px solid #e4b359;"><strong>${exp.job_title || '未知職稱'}</strong> <span style="color:#888;font-size:9pt">${exp.years || ''}</span><br/>${exp.achievements || ''}</div>`).join('')
            : '<p>無工作經歷資料</p>';

        const qaHtml = (answers || []).map((a, i) =>
            `<div style="margin-bottom:1.2em;"><div style="font-weight:bold;color:#2d221c">Q${i + 1}. ${questionMap[a.question_code] || a.question_code}</div><div style="background:#fffdf5;padding:0.6em 0.9em;margin-top:0.4em;border-left:3px solid #e4b359;white-space:pre-wrap">${a.answer_text || ''}</div></div>`
        ).join('');

        const fpaHtml = personality
            ? `<p>🔴 紅色 ${personality.red_score ?? 0}　🟡 黃色 ${personality.yellow_score ?? 0}　🟢 綠色 ${personality.green_score ?? 0}　🔵 藍色 ${personality.blue_score ?? 0}　⚡ CRI ${personality.cri_score ?? 0}/10</p>`
            : '<p>尚未完成測驗</p>';

        const resumeTextHtml = candidate.resume_text
            ? candidate.resume_text
                .replace(/</g, '&lt;').replace(/>/g, '&gt;')
                .split(/\n{2,}/)
                .map(para => `<p style="margin:0 0 0.8em;line-height:1.75">${para.replace(/\n/g, '<br/>')}</p>`)
                .join('')
            : '<p style="color:#888">無外部上傳履歷</p>';

        const aiHtml = aiReport?.raw_analysis
            ? aiReport.raw_analysis
                .replace(/^### (.+)$/gm, '<h3>$1</h3>')
                .replace(/^## (.+)$/gm, '<h2>$1</h2>')
                .replace(/^# (.+)$/gm, '<h1 style="font-size:14pt;border-bottom:2px solid #e4b359;padding-bottom:4px;margin-top:1.5em">$1</h1>')
                .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
                .replace(/^> (.+)$/gm, '<blockquote style="border-left:3px solid #e4b359;padding:0.3em 0.8em;margin:0.5em 0;background:#fffdf5">$1</blockquote>')
                .replace(/^- (.+)$/gm, '<li>$1</li>')
                .replace(/\n\n/g, '</p><p>')
            : '<p style="color:#888">AI 尚未產生分析報告</p>';

        const win = window.open('', '_blank');
        win.document.write(`<!DOCTYPE html><html lang="zh-TW"><head><meta charset="UTF-8"><title>${candidate.name} - 評鑑報告</title>
<style>@page{size:A4;margin:1.5cm}body{font-family:'Microsoft JhengHei',sans-serif;font-size:10pt;color:#2d221c;line-height:1.7}h1{font-size:15pt;border-bottom:2px solid #e4b359;padding-bottom:4px;margin-top:1.5em}h2{font-size:12pt;margin-top:1.2em}h3{font-size:10.5pt;color:#c07a10;margin-top:1em}section{border:1px solid #ddd;padding:1em;margin-bottom:1.2em;page-break-inside:avoid}.title{font-size:20pt;font-weight:bold;margin:0}.sub{color:#888;font-size:9pt;margin:0 0 1.5em 0}blockquote{border-left:3px solid #e4b359;padding:0.3em 0.8em;margin:0.4em 0;background:#fffdf5}strong{color:#c07a10}p{margin:0 0 0.6em}</style></head>
<body>
<p class="title">${candidate.name}</p>
<p class="sub">應徵：${candidate.department || ''} - ${candidate.position || ''}　|　狀態：${candidate.status || '待處理'}　|　電話：${candidate.phone || ''}</p>

<section><h2>📋 基本資料</h2>
<p>學歷：${candidate.education_school || ''} ${candidate.education_major || ''}　|　駕照：${candidate.driving_license || '無'}</p>
<p>目前薪資：${candidate.current_salary_monthly || 'N/A'} / 月　|　期望薪資：${candidate.expected_salary_monthly || 'N/A'} / 月</p>
<p>離職原因：${candidate.leave_reason || '未填'}</p>
<p>應徵動機：${candidate.motivation || '未填'}</p>
<p>職涯規劃：${candidate.career_plan_short || '-'} → ${candidate.career_plan_mid || '-'} → ${candidate.career_plan_long || '-'}</p>
</section>

<section><h2>📎 外部上傳履歷（制式履歷原文）</h2>${resumeTextHtml}</section>

<section><h2>💼 工作經歷</h2>${workExpHtml}</section>

<section><h2>📝 問答紀錄</h2>${qaHtml}</section>

<section><h2>🧬 FPA 性格測驗</h2>${fpaHtml}</section>

<section><h2>🤖 AI 人才評鑑報告</h2>${aiHtml}</section>
</body></html>`);
        win.document.close();
        setTimeout(() => win.print(), 400);
    };

    // ── GUARDS ──
    if (loading) return <div style={{ padding: '3rem', display: 'flex', alignItems: 'center', gap: '12px', color: 'var(--color-primary)', justifyContent: 'center', fontFamily: 'var(--font-tech)', fontSize: '1.1rem' }}><Loader2 className="animate-spin" /> 載入中...</div>;
    if (error || !data) return <div style={{ padding: '3rem', color: 'var(--color-error)', fontFamily: 'var(--font-tech)', textAlign: 'center' }}>[ERROR] {error || '找不到求職者'}</div>;

    const { candidate, workExperiences, answers, personality, aiReport, evaluations } = data;

    // ── Tabs Config ──
    const TABS = [
        { key: 'candidate', icon: <FileText size={17} />, label: '候選人資料' },
        { key: 'resume104', icon: <FileUp size={17} />, label: '104履歷' },
        { key: 'hr', icon: <ClipboardList size={17} />, label: 'HR 評估中心' },
    ];

    return (
        <div style={{ padding: '2.5rem', maxWidth: '1440px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>

            {/* ── Full-page AI overlay ── */}
            {aiGenerating && createPortal(
                <div style={{ position: 'fixed', inset: 0, zIndex: 9998, background: 'rgba(15,10,5,0.78)', backdropFilter: 'blur(8px)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '2rem' }}>
                    <div style={{ width: '80px', height: '80px', border: '4px solid rgba(228,179,89,0.2)', borderTop: '4px solid var(--color-primary)', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
                    <div style={{ textAlign: 'center', color: '#fff' }}>
                        <div style={{ fontFamily: 'var(--font-heading)', fontSize: '1.8rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>AI 深度分析中...</div>
                        <div style={{ fontFamily: 'var(--font-tech)', fontSize: '0.9rem', color: 'rgba(255,255,255,0.5)', maxWidth: '380px' }}>正在整合履歷、問答與性格測驗，產出八大章節完整報告</div>
                        <div style={{ marginTop: '1rem', display: 'flex', justifyContent: 'center', gap: '8px' }}>
                            {[0, 1, 2, 3, 4].map(i => (
                                <div key={i} style={{ width: '8px', height: '8px', borderRadius: '50%', background: 'var(--color-primary)', animation: `pulse 1.4s ease-in-out ${i * 0.25}s infinite` }} />
                            ))}
                        </div>
                        <div style={{ marginTop: '1rem', fontFamily: 'var(--font-tech)', fontSize: '0.78rem', color: 'rgba(255,255,255,0.3)' }}>預計 30 ~ 60 秒，請勿關閉頁面</div>
                    </div>
                </div>,
                document.body
            )}

            {/* ── Header ── */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '2px solid var(--border-structural)', paddingBottom: '1.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem' }}>
                    <button
                        onClick={() => navigate(-1)}
                        style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid var(--border-structural)', background: 'transparent', width: '48px', height: '48px', cursor: 'pointer', transition: 'all 0.2s', color: 'var(--color-structural)', borderRadius: '4px' }}
                        onMouseEnter={e => { e.currentTarget.style.background = 'var(--color-structural)'; e.currentTarget.style.color = 'white'; }}
                        onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--color-structural)'; }}
                    >
                        <ArrowLeft size={22} />
                    </button>
                    <div>
                        <h1 className="step-title" style={{ fontSize: '2.2rem', margin: '0 0 0.4rem 0' }}>{candidate.name}</h1>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                            <span style={{ fontSize: '0.9rem', color: 'rgba(45,34,28,0.55)', fontFamily: 'var(--font-tech)' }}>
                                {candidate.department || '未指定'} · {candidate.position || '未指定'}
                            </span>
                            {/* ── 甄試狀態（唯讀，與 AdminDashboard 同步） ── */}
                            <StatusBadge status={candidate.status} />
                            <span style={{ fontSize: '0.78rem', color: 'rgba(45,34,28,0.35)', fontFamily: 'var(--font-tech)' }}>可於看板拖曳更新狀態</span>
                        </div>
                    </div>
                </div>
                <button
                    className="btn-wizard-next no-print"
                    onClick={handlePrint}
                    style={{ background: 'var(--color-structural)', color: 'var(--color-primary)', padding: '0.7rem 1.4rem', margin: 0, fontSize: '0.95rem', width: 'auto', display: 'flex', alignItems: 'center', gap: '8px' }}
                >
                    <Printer size={18} />列印 / 匯出 PDF
                </button>
            </div>

            {/* ── Tab Bar ── */}
            <div style={{ display: 'flex', gap: '0', borderBottom: '2px solid var(--border-structural)', marginBottom: '0.5rem' }}>
                {TABS.map(tab => (
                    <button
                        key={tab.key}
                        onClick={() => setActiveTab(tab.key)}
                        style={{
                            display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.85rem 2rem',
                            border: 'none', background: 'transparent', cursor: 'pointer', fontSize: '1rem', fontWeight: activeTab === tab.key ? 'bold' : '500',
                            color: activeTab === tab.key ? 'var(--color-structural)' : 'rgba(45,34,28,0.45)',
                            borderBottom: activeTab === tab.key ? '3px solid var(--color-primary)' : '3px solid transparent',
                            marginBottom: '-2px', transition: 'all 0.15s', fontFamily: 'var(--font-heading)',
                        }}
                        onMouseEnter={e => { if (activeTab !== tab.key) e.currentTarget.style.color = 'var(--color-structural)'; }}
                        onMouseLeave={e => { if (activeTab !== tab.key) e.currentTarget.style.color = 'rgba(45,34,28,0.45)'; }}
                    >
                        {tab.icon} {tab.label}
                    </button>
                ))}
            </div>

            {/* ══════════════ TAB: 候選人資料 ══════════════ */}
            {activeTab === 'candidate' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>

                    {/* Basic Info */}
                    <div className="wizard-content" style={{ minHeight: 'auto', padding: '2rem' }}>
                        <h2 style={{ fontSize: '1.4rem', margin: '0 0 1.5rem 0', display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)', borderBottom: '2px solid rgba(45,34,28,0.08)', paddingBottom: '0.9rem' }}>
                            <Briefcase size={22} color="var(--color-primary)" /> 基本資料
                        </h2>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.2rem', fontSize: '0.95rem' }}>
                            {[
                                { label: '聯絡電話', value: candidate.phone },
                                { label: '出生日期', value: candidate.birth_date || '未提供' },
                                { label: '最高學歷', value: `${candidate.education_school || ''} ${candidate.education_major ? `(${candidate.education_major})` : ''}` },
                                { label: '駕照', value: candidate.driving_license || '無' },
                                { label: '目前薪資', value: `月 ${candidate.current_salary_monthly || 'N/A'} / 年 ${candidate.current_salary_annual || 'N/A'}` },
                                { label: '期望薪資', value: `月 ${candidate.expected_salary_monthly || 'N/A'} / 年 ${candidate.expected_salary_annual || 'N/A'}` },
                            ].map(f => (
                                <div key={f.label}>
                                    <div style={{ color: 'rgba(45,34,28,0.5)', fontSize: '0.78rem', fontFamily: 'var(--font-tech)', marginBottom: '0.2rem', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{f.label}</div>
                                    <div style={{ fontWeight: 600, color: 'var(--color-structural)' }}>{f.value}</div>
                                </div>
                            ))}
                        </div>
                        <div style={{ marginTop: '1.5rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', borderTop: '1px solid rgba(45,34,28,0.08)', paddingTop: '1.2rem' }}>
                            {[
                                { label: '專業技能', value: candidate.skills },
                                { label: '考取證照', value: candidate.certifications },
                                { label: '離職原因', value: candidate.leave_reason },
                                { label: '應徵動機', value: candidate.motivation },
                                { label: '人生夢想', value: candidate.dream },
                            ].map(f => (
                                <div key={f.label}>
                                    <div style={{ color: 'rgba(45,34,28,0.5)', fontSize: '0.78rem', fontFamily: 'var(--font-tech)', marginBottom: '0.2rem' }}>{f.label}</div>
                                    <div style={{ fontWeight: 500, color: 'var(--color-structural)', whiteSpace: 'pre-wrap', lineHeight: 1.6 }}>{f.value || '未填寫'}</div>
                                </div>
                            ))}
                        </div>
                        <div style={{ marginTop: '1rem', display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1rem', borderTop: '1px solid rgba(45,34,28,0.08)', paddingTop: '1.2rem' }}>
                            {[
                                { label: '短程目標（1年內）', value: candidate.career_plan_short },
                                { label: '中程目標（3～5年）', value: candidate.career_plan_mid },
                                { label: '長程目標（5年後）', value: candidate.career_plan_long },
                            ].map(f => (
                                <div key={f.label} style={{ background: 'rgba(228,179,89,0.04)', border: '1px solid rgba(228,179,89,0.2)', borderRadius: '8px', padding: '0.85rem 1rem' }}>
                                    <div style={{ color: 'rgba(45,34,28,0.5)', fontSize: '0.78rem', fontFamily: 'var(--font-tech)', marginBottom: '0.4rem' }}>{f.label}</div>
                                    <div style={{ fontWeight: 500, color: 'var(--color-structural)' }}>{f.value || '未填寫'}</div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Work Experiences */}
                    <div className="wizard-content" style={{ minHeight: 'auto', padding: '2rem' }}>
                        <h2 style={{ fontSize: '1.4rem', margin: '0 0 1.5rem 0', display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)', borderBottom: '2px solid rgba(45,34,28,0.08)', paddingBottom: '0.9rem' }}>
                            <Briefcase size={22} color="var(--color-primary)" /> 工作經歷
                            <span style={{ marginLeft: 'auto', fontSize: '0.85rem', color: 'rgba(45,34,28,0.4)', fontFamily: 'var(--font-tech)' }}>共 {workExperiences?.length || 0} 筆</span>
                        </h2>
                        {workExperiences?.length > 0 ? (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                {workExperiences.map((exp, idx) => (
                                    <div key={idx} style={{ background: 'rgba(255,255,255,0.4)', padding: '1.4rem', border: '1px solid var(--border-structural)', borderLeft: '4px solid var(--color-structural)', borderRadius: '0 6px 6px 0' }}>
                                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
                                            <div style={{ fontWeight: '700', color: 'var(--color-structural)', fontSize: '1.1rem', fontFamily: 'var(--font-heading)' }}>{exp.job_title || '未填寫職稱'}</div>
                                            <span style={{ background: 'rgba(228,179,89,0.12)', color: 'var(--color-primary)', padding: '2px 10px', borderRadius: '12px', fontSize: '0.85rem', fontWeight: 'bold' }}>{exp.years || '-'}</span>
                                        </div>
                                        {exp.achievements && <div style={{ color: 'var(--color-structural)', whiteSpace: 'pre-wrap', lineHeight: '1.8', fontSize: '0.95rem', background: 'rgba(228,179,89,0.03)', padding: '0.75rem', borderRadius: '4px' }}>{exp.achievements}</div>}
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div style={{ color: 'rgba(45,34,28,0.4)', fontFamily: 'var(--font-tech)', textAlign: 'center', padding: '2rem' }}>尚無工作經歷資料</div>
                        )}
                    </div>

                    {/* QA */}
                    <div className="wizard-content" style={{ minHeight: 'auto', padding: '2rem' }}>
                        <h2 style={{ fontSize: '1.4rem', margin: '0 0 1.5rem 0', display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)', borderBottom: '2px solid rgba(45,34,28,0.08)', paddingBottom: '0.9rem' }}>
                            <FileText size={22} color="var(--color-primary)" /> 專業職能問答
                            <span style={{ marginLeft: 'auto', fontSize: '0.85rem', color: 'rgba(45,34,28,0.4)', fontFamily: 'var(--font-tech)' }}>共 {answers?.length || 0} 題</span>
                        </h2>
                        {answers?.length > 0 ? (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1.2rem' }}>
                                {answers.map((ans, idx) => (
                                    <div key={idx} style={{ background: 'rgba(255,255,255,0.4)', padding: '1.4rem', border: '1px solid var(--border-structural)', borderLeft: '4px solid var(--color-primary)', borderRadius: '0 6px 6px 0' }}>
                                        <div style={{ fontWeight: '700', color: 'var(--color-structural)', marginBottom: '0.75rem', fontSize: '1rem', fontFamily: 'var(--font-heading)' }}>
                                            <span style={{ color: 'var(--color-primary)', marginRight: '6px' }}>Q{idx + 1}.</span>
                                            {questionMap[ans.question_code] || ans.question_code}
                                        </div>
                                        <div style={{ color: 'var(--color-structural)', whiteSpace: 'pre-wrap', lineHeight: '1.8', fontSize: '0.95rem', background: 'rgba(228,179,89,0.04)', padding: '0.75rem', borderRadius: '4px' }}>{ans.answer_text}</div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div style={{ color: 'rgba(45,34,28,0.4)', fontFamily: 'var(--font-tech)', textAlign: 'center', padding: '2rem' }}>尚無問答紀錄</div>
                        )}
                    </div>
                </div>
            )}

            {/* ══════════════ TAB: 104履歷 ══════════════ */}
            {activeTab === 'resume104' && (
                <div className="wizard-content" style={{ minHeight: 'auto', padding: '1.5rem' }}>
                    <h2 style={{ fontSize: '1.4rem', margin: '0 0 1rem 0', display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)', borderBottom: '2px solid rgba(45,34,28,0.08)', paddingBottom: '0.9rem' }}>
                        <FileUp size={22} color="var(--color-primary)" /> 104履歷原件
                        <span style={{ marginLeft: 'auto', fontSize: '0.78rem', color: 'rgba(45,34,28,0.35)', fontFamily: 'var(--font-tech)' }}>重新上傳可更新履歷；支援 PDF / Word</span>
                    </h2>
                    {candidate.resume_text ? (
                        <iframe
                            key={id}
                            src={`${apiUrl}/admin/candidates/${id}/resume-file?t=${Date.now()}`}
                            title="104履歷"
                            style={{
                                width: '100%',
                                height: '85vh',
                                border: '1px solid rgba(45,34,28,0.12)',
                                borderRadius: '6px',
                                background: '#fff'
                            }}
                        />
                    ) : (
                        <div style={{ padding: '4rem', textAlign: 'center', color: 'rgba(45,34,28,0.4)', fontFamily: 'var(--font-tech)', border: '2px dashed rgba(45,34,28,0.15)', borderRadius: '8px' }}>
                            <FileUp size={40} style={{ opacity: 0.2, marginBottom: '1rem' }} />
                            <div style={{ fontWeight: 'bold', marginBottom: '0.4rem' }}>尚未上傳 104 履歷</div>
                            <div style={{ fontSize: '0.82rem' }}>請在「候選人資料 → HR 評估中心」的履歷上傳區塊上傳 PDF 或 Word</div>
                        </div>
                    )}
                </div>
            )}

            {/* ══════════════ TAB: HR 評估中心 ══════════════ */}
            {activeTab === 'hr' && (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '2rem', alignItems: 'start' }}>

                    {/* ── Left: AI Report ── */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>

                        {/* FPA */}
                        {personality && (
                            <div className="wizard-content" style={{ minHeight: 'auto', padding: '1.5rem' }}>
                                <h3 style={{ fontSize: '0.9rem', color: 'var(--color-structural)', fontFamily: 'var(--font-tech)', margin: '0 0 1rem 0', letterSpacing: '1px' }}>// 嘉樂 FPA 四色性格測驗結果</h3>
                                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '0.75rem' }}>
                                    {[
                                        { key: 'red', label: '🔴 紅色', sub: '熱情外向', color: '#ef4444' },
                                        { key: 'yellow', label: '🟡 黃色', sub: '目標導向', color: '#eab308' },
                                        { key: 'green', label: '🟢 綠色', sub: '穩定和諧', color: '#22c55e' },
                                        { key: 'blue', label: '🔵 藍色', sub: '謹慎分析', color: '#3b82f6' },
                                        { key: 'cri', label: '⚡ CRI', sub: '真實度', color: '#8b5cf6' },
                                    ].map(({ key, label, sub, color }) => (
                                        <div key={key} style={{ background: 'rgba(255,255,255,0.7)', padding: '1rem 0.5rem', display: 'flex', flexDirection: 'column', alignItems: 'center', borderBottom: `4px solid ${color}`, borderRadius: '4px 4px 0 0', textAlign: 'center' }}>
                                            <span style={{ fontSize: '0.82rem', fontWeight: 700, marginBottom: '0.2rem' }}>{label}</span>
                                            <span style={{ fontSize: '0.68rem', color: 'rgba(45,34,28,0.45)', marginBottom: '0.4rem' }}>{sub}</span>
                                            <strong style={{ fontSize: '1.8rem', color: 'var(--color-structural)', fontFamily: 'var(--font-tech)' }}>{personality[`${key}_score`] ?? 0}</strong>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* AI Report */}
                        <div className="wizard-content" style={{ minHeight: 'auto', padding: '2rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', borderBottom: '2px solid rgba(45,34,28,0.08)', paddingBottom: '1rem' }}>
                                <h2 style={{ fontSize: '1.4rem', margin: 0, display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)' }}>
                                    <BrainCircuit size={22} color="var(--color-primary)" /> AI 人才評鑑報告
                                </h2>
                                <button
                                    className="btn-wizard-next no-print"
                                    onClick={handleRegenerateAi}
                                    disabled={aiGenerating}
                                    style={{ padding: '0.5rem 1.1rem', fontSize: '0.88rem', width: 'auto', display: 'flex', gap: '6px', opacity: aiGenerating ? 0.5 : 1 }}
                                >
                                    <RefreshCw size={15} style={{ animation: aiGenerating ? 'spin 1s linear infinite' : 'none' }} />
                                    {aiGenerating ? '分析中...' : '重新產生'}
                                </button>
                            </div>

                            {aiReport ? (
                                <div style={{ background: 'rgba(228,179,89,0.02)', border: '1px solid rgba(228,179,89,0.25)', padding: '2rem', borderRadius: '6px', color: 'var(--color-structural)', lineHeight: '1.9', fontSize: '0.96rem' }}>
                                    <ReactMarkdown remarkPlugins={[remarkGfm]} components={MD_COMPONENTS}>
                                        {aiReport.raw_analysis}
                                    </ReactMarkdown>
                                </div>
                            ) : (
                                <div style={{ color: 'rgba(45,34,28,0.45)', fontFamily: 'var(--font-tech)', padding: '3rem', textAlign: 'center', border: '1px dashed rgba(45,34,28,0.2)', borderRadius: '8px' }}>
                                    <BrainCircuit size={36} style={{ marginBottom: '1rem', opacity: 0.25 }} />
                                    <div>尚未產生 AI 分析報告</div>
                                    <div style={{ fontSize: '0.82rem', marginTop: '0.5rem', opacity: 0.7 }}>點擊右上方「重新產生」按鈕觸發</div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* ── Right Sidebar: HR Tools ── */}
                    <div style={{ position: 'sticky', top: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>

                        {/* Resume Upload */}
                        <div className="wizard-content" style={{ minHeight: 'auto', padding: '1.4rem' }}>
                            <h3 style={{ fontSize: '0.88rem', margin: '0 0 1rem 0', display: 'flex', alignItems: 'center', gap: '8px', color: 'var(--color-structural)', fontFamily: 'var(--font-tech)', letterSpacing: '0.5px' }}>
                                <FileUp size={16} color="var(--color-primary)" /> // 外部履歷上傳（PDF / Word）
                            </h3>
                            <div
                                style={{ border: '2px dashed var(--border-structural)', borderRadius: '8px', padding: '1.2rem', textAlign: 'center', background: 'rgba(228,179,89,0.02)', cursor: 'pointer', transition: 'all 0.2s' }}
                                onDragOver={e => { e.preventDefault(); e.currentTarget.style.borderColor = 'var(--color-primary)'; }}
                                onDragLeave={e => { e.currentTarget.style.borderColor = 'var(--border-structural)'; }}
                                onDrop={e => { e.preventDefault(); e.currentTarget.style.borderColor = 'var(--border-structural)'; const f = e.dataTransfer.files[0]; if (f) handleResumeUpload(f); }}
                                onClick={() => document.getElementById(`resume-hr-${id}`).click()}
                            >
                                <input id={`resume-hr-${id}`} type="file" accept=".pdf,.doc,.docx" style={{ display: 'none' }} onChange={e => { const f = e.target.files[0]; if (f) handleResumeUpload(f); e.target.value = ''; }} />
                                {uploadState.loading ? (
                                    <div style={{ color: 'var(--color-primary)', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}><Loader2 size={18} className="animate-spin" /> 解析中...</div>
                                ) : (
                                    <div style={{ color: 'rgba(45,34,28,0.5)', fontSize: '0.85rem' }}>
                                        <Upload size={22} style={{ margin: '0 auto 0.4rem' }} />
                                        <div style={{ fontWeight: 'bold', color: 'var(--color-structural)', marginBottom: '0.2rem' }}>點擊或拖曳檔案</div>
                                        <div style={{ fontSize: '0.75rem' }}>上傳後自動納入 AI 評估</div>
                                    </div>
                                )}
                            </div>
                            {uploadState.success && <div style={{ marginTop: '0.6rem', fontSize: '0.8rem', color: '#15803d', display: 'flex', alignItems: 'center', gap: '4px' }}><CheckCircle size={13} /> {uploadState.success}</div>}
                            {uploadState.error && <div style={{ marginTop: '0.6rem', fontSize: '0.8rem', color: '#dc2626', display: 'flex', alignItems: 'center', gap: '4px' }}><XCircle size={13} /> {uploadState.error}</div>}
                            {candidate.resume_text && (
                                <div style={{ marginTop: '0.75rem', padding: '0.55rem 0.8rem', background: 'rgba(34,197,94,0.05)', border: '1px solid rgba(34,197,94,0.3)', borderRadius: '6px', fontSize: '0.8rem' }}>
                                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '4px' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontWeight: 'bold', color: '#15803d' }}><CheckCircle size={12} /> 已上傳：{candidate.resume_text.length.toLocaleString()} 字元</div>
                                        <button
                                            onClick={handleDeleteResume}
                                            title="刪除此份履歷"
                                            style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '3px 8px', border: '1px solid rgba(220,38,38,0.35)', borderRadius: '4px', background: 'rgba(220,38,38,0.06)', color: '#dc2626', cursor: 'pointer', fontSize: '0.72rem', fontWeight: 'bold', transition: 'all 0.15s' }}
                                            onMouseEnter={e => { e.currentTarget.style.background = 'rgba(220,38,38,0.14)'; }}
                                            onMouseLeave={e => { e.currentTarget.style.background = 'rgba(220,38,38,0.06)'; }}
                                        >
                                            <Trash2 size={11} /> 刪除
                                        </button>
                                    </div>
                                    <div style={{ color: 'rgba(45,34,28,0.45)', fontSize: '0.72rem', marginTop: '2px' }}>重新上傳可覆蓋更新</div>
                                </div>
                            )}
                        </div>

                        {/* Interview Score Form section (now includes Evaluations) */}
                        <div style={{ marginBottom: '1rem' }}>
                            <InterviewScoreForm
                                candidateId={id}
                                apiUrl={apiUrl}
                                evaluations={data.evaluations || []}
                                newComment={newComment}
                                setNewComment={setNewComment}
                                handleAddEvaluation={handleAddEvaluation}
                                commenting={commenting}
                            />
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CandidateDetail;

import React, { useState, useEffect } from 'react';
import { Plus, Edit, Trash2, Save, X, Briefcase, MapPin, DollarSign, Clock, Users, Building, FileText, CheckCircle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

const JobManagement = () => {
    const { user } = useAuth();
    const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001/api/v1';

    const [categories, setCategories] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingId, setEditingId] = useState(null);

    // Form State
    const defaultFormData = {
        department: '',
        position: '',
        stages: [
            { name: '新進履歷', stages: ['待處理'] },
            { name: '初篩階段', stages: ['初篩合格'] },
            { name: '面試階段', stages: ['邀約面試', '已面試'] },
            { name: '錄取作業', stages: ['錄用作業中', '已報到', '未報到', '未錄取'] }
        ],
        details: {
            jobCategory: '',
            jobType: '全職', // 全職, 兼職, 實習
            location: '',
            salary: '',
            workingHours: '',
            vacationPolicy: '週休二日',
            dateToStart: '不限',
            headcount: '1',
            description: '',
            requirements: '',
            contactInfo: ''
        }
    };
    const [formData, setFormData] = useState(defaultFormData);
    const [submitLoading, setSubmitLoading] = useState(false);

    useEffect(() => {
        fetchCategories();
    }, []);

    const fetchCategories = async () => {
        try {
            const response = await fetch(`${apiUrl}/categories`, { cache: 'no-store' });
            if (!response.ok) throw new Error('Failed to fetch jobs');
            const data = await response.json();
            setCategories(data.data || []);
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (job = null) => {
        if (job) {
            setEditingId(job.id);
            setFormData({
                department: job.department || '',
                position: job.position || '',
                stages: job.stages && job.stages.length > 0 ? job.stages : defaultFormData.stages,
                details: {
                    ...defaultFormData.details,
                    ...(job.details || {})
                }
            });
        } else {
            setEditingId(null);
            setFormData(defaultFormData);
        }
        setIsModalOpen(true);
    };

    const handleDetailChange = (field, value) => {
        setFormData(prev => ({
            ...prev,
            details: { ...prev.details, [field]: value }
        }));
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setSubmitLoading(true);
        try {
            const url = editingId ? `${apiUrl}/admin/job-categories/${editingId}` : `${apiUrl}/admin/job-categories`;
            const method = editingId ? 'PUT' : 'POST';

            const response = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${localStorage.getItem('adminToken')}`
                },
                body: JSON.stringify(formData)
            });

            if (!response.ok) {
                const data = await response.json();
                throw new Error(data.error || '儲存失敗');
            }

            setIsModalOpen(false);
            fetchCategories();
        } catch (err) {
            alert(err.message);
        } finally {
            setSubmitLoading(false);
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('確定要刪除此職缺嗎？若該職缺下有求職者將無法刪除。')) return;
        try {
            const response = await fetch(`${apiUrl}/admin/job-categories/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${localStorage.getItem('adminToken')}` }
            });
            if (!response.ok) {
                const data = await response.json();
                throw new Error(data.error || '刪除失敗');
            }
            fetchCategories();
        } catch (err) {
            alert(err.message);
        }
    };

    if (loading) return <div style={{ padding: '3rem', textAlign: 'center', color: 'rgba(45,34,28,0.5)' }}>Loading Jobs...</div>;

    return (
        <div style={{ padding: '3rem', margin: '0 auto', display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', borderBottom: '1px solid var(--border-structural)', paddingBottom: '1rem', marginBottom: '1.5rem', flexShrink: 0 }}>
                <div>
                    <h1 className="step-title" style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>職缺管理中心</h1>
                    <p className="step-desc" style={{ margin: 0 }}>管理對外招募的職缺需求設定與詳細招募條件。</p>
                </div>
                <button onClick={() => handleOpenModal()} className="btn-wizard-next" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.6rem 1.2rem', marginBottom: '0', fontSize: '0.95rem' }}>
                    <Plus size={18} /> 新增職缺
                </button>
            </div>

            {/* List */}
            <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '1rem', paddingRight: '1rem' }}>
                {error && <div style={{ color: 'var(--color-error)', background: 'rgba(224, 49, 49, 0.1)', padding: '1rem', borderRadius: '4px' }}>{error}</div>}

                {categories.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '4rem', color: 'rgba(45,34,28,0.4)', background: 'var(--bg-card)', borderRadius: '8px' }}>
                        尚未建立任何職缺，請點擊右上角新增。
                    </div>
                ) : (
                    categories.map(job => (
                        <div key={job.id} style={{ background: 'var(--bg-card)', border: '1px solid var(--border-structural)', borderRadius: '12px', padding: '1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 4px 12px rgba(0,0,0,0.02)' }}>
                            <div style={{ flex: 1 }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.8rem' }}>
                                    <h3 style={{ margin: 0, fontSize: '1.4rem', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)' }}>{job.position}</h3>
                                    <span style={{ background: '#EAF6F6', color: 'var(--color-accent-mint)', padding: '4px 12px', borderRadius: '6px', fontSize: '0.85rem', fontWeight: 'bold' }}>
                                        {job.department}
                                    </span>
                                </div>
                                <div style={{ display: 'flex', gap: '1.5rem', color: 'rgba(24,24,27,0.6)', fontSize: '0.9rem', flexWrap: 'wrap' }}>
                                    <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Briefcase size={14} /> {job.details?.jobType || '全職'}</span>
                                    {job.details?.location && <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><MapPin size={14} /> {job.details.location}</span>}
                                    {job.details?.salary && <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><DollarSign size={14} /> {job.details.salary}</span>}
                                    <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Users size={14} /> 需求 {job.details?.headcount || '1'} 人</span>
                                </div>
                            </div>
                            <div style={{ display: 'flex', gap: '0.8rem', paddingLeft: '2rem' }}>
                                <button onClick={() => handleOpenModal(job)} className="btn-secondary" style={{ padding: '0.6rem 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                    <Edit size={16} /> 編輯
                                </button>
                                <button onClick={() => handleDelete(job.id)} style={{ background: 'transparent', border: '1px solid var(--color-error)', color: 'var(--color-error)', padding: '0.6rem 1rem', borderRadius: '8px', cursor: 'pointer', transition: 'all 0.2s', display: 'flex', alignItems: 'center', gap: '0.5rem' }} onMouseEnter={e => e.currentTarget.style.background = 'rgba(224,49,49,0.1)'} onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(24, 24, 27, 0.4)', backdropFilter: 'blur(8px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '2rem' }}>
                    <div style={{ background: 'var(--bg-main)', width: '100%', maxWidth: '900px', maxHeight: '90vh', borderRadius: '12px', display: 'flex', flexDirection: 'column', boxShadow: '0 25px 50px rgba(0,0,0,0.15)', border: '1px solid rgba(255,255,255,0.2)' }}>
                        <div style={{ padding: '1.5rem 2rem', borderBottom: '1px solid var(--border-structural)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'var(--bg-card)', borderRadius: '12px 12px 0 0' }}>
