                                    <label className="form-label">薪資待遇</label>
                                    <input type="text" className="form-input" value={formData.details.salary} onChange={e => handleDetailChange('salary', e.target.value)} placeholder="例如: 月薪 40,000 ~ 60,000 元" />

                                    <label className="form-label">需求人數</label>
                                    <input type="text" className="form-input" value={formData.details.headcount} onChange={e => handleDetailChange('headcount', e.target.value)} placeholder="例如: 1 ~ 2 人" />
                                </div>

                                {/* Details Right Column */}
                                <div>
                                    <label className="form-label">上班時段</label>
                                    <input type="text" className="form-input" value={formData.details.workingHours} onChange={e => handleDetailChange('workingHours', e.target.value)} placeholder="例如: 白班 09:00~18:00" />

                                    <label className="form-label">休假制度</label>
                                    <input type="text" className="form-input" value={formData.details.vacationPolicy} onChange={e => handleDetailChange('vacationPolicy', e.target.value)} placeholder="例如: 週休二日" />

                                    <label className="form-label">可上班日</label>
                                    <input type="text" className="form-input" value={formData.details.dateToStart} onChange={e => handleDetailChange('dateToStart', e.target.value)} placeholder="例如: 一個月內、隨時" />

                                    <label className="form-label">聯絡資訊</label>
                                    <input type="text" className="form-input" value={formData.details.contactInfo} onChange={e => handleDetailChange('contactInfo', e.target.value)} placeholder="聯絡人姓名與信箱" />
                                </div>

                                {/* Textareas */}
                                <div style={{ gridColumn: '1 / -1' }}>
                                    <label className="form-label">職務說明書 (Job Description)</label>
                                    <textarea className="form-input" rows={5} value={formData.details.description} onChange={e => handleDetailChange('description', e.target.value)} placeholder="描述工作內容、日常職責等..." style={{ resize: 'vertical' }}></textarea>
                                </div>

                                <div style={{ gridColumn: '1 / -1' }}>
                                    <label className="form-label">條件要求 (Requirements)</label>
                                    <textarea className="form-input" rows={5} value={formData.details.requirements} onChange={e => handleDetailChange('requirements', e.target.value)} placeholder="描述技能需求、學經歷限制、語文條件等..." style={{ resize: 'vertical' }}></textarea>
                                </div>
                            </form>
                        </div>

                        <div style={{ padding: '1.5rem 2rem', borderTop: '1px solid var(--border-structural)', display: 'flex', justifyContent: 'space-between', background: 'var(--bg-card)', borderRadius: '0 0 8px 8px' }}>
                            <p style={{ margin: 0, color: 'rgba(45,34,28,0.5)', fontSize: '0.85rem' }}>* 甄試流程預設為標準模板，可至【甄試】看板的行內編輯器修改流程階段。</p>
                            <div style={{ display: 'flex', gap: '1rem' }}>
                                <button type="button" onClick={() => setIsModalOpen(false)} className="btn-secondary">取消</button>
                                <button type="submit" form="jobForm" disabled={submitLoading} className="btn-wizard-next" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', margin: 0 }}>
                                    <Save size={16} /> {submitLoading ? '儲存中...' : '儲存職缺'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default JobManagement;

import React, { useState, useEffect } from 'react';
import { Search, Filter, UserCircle, Briefcase, Calendar, ChevronRight, Trash2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const ResumeManagement = () => {
    const navigate = useNavigate();
    const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:3001/api/v1';

    const [candidates, setCandidates] = useState([]);
    const [categories, setCategories] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('ALL');
    const [jobFilter, setJobFilter] = useState('ALL');

    useEffect(() => { fetchData(); }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const token = localStorage.getItem('adminToken');
            const [candRes, catRes] = await Promise.all([
                fetch(`${apiUrl}/admin/candidates`, { headers: { 'Authorization': `Bearer ${token}` }, cache: 'no-store' }),
                fetch(`${apiUrl}/categories`, { cache: 'no-store' })
            ]);
            if (!candRes.ok) throw new Error('無法載入履歷資料');
            const candData = await candRes.json();
            let catData = { data: [] };
            if (catRes.ok) catData = await catRes.json();
            setCandidates(candData.data || []);
            setCategories(catData.data || []);
        } catch (err) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteCandidate = async (e, candidateId, candidateName) => {
        e.stopPropagation();
        if (!window.confirm(`確定要刪除「${candidateName}」的所有資料嗎？\n此操作無法復原，問答、評分、AI 報告等資料都將一併刪除。`)) return;
        try {
            const token = localStorage.getItem('adminToken');
            const res = await fetch(`${apiUrl}/admin/candidates/${candidateId}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${token}` }
            });
            if (!res.ok) { const j = await res.json(); throw new Error(j.error || '刪除失敗'); }
            setCandidates(prev => prev.filter(c => c.id !== candidateId));
        } catch (err) {
            alert('錯誤：' + err.message);
        }
    };

    const getJobName = (categoryId) => {
        if (!categoryId) return '未指派職缺';
        const cat = categories.find(c => c.id === categoryId);
        return cat ? `${cat.department} - ${cat.position}` : '未知職缺';
    };

    const filteredCandidates = candidates.filter(c => {
        const matchSearch = c.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            c.phone?.includes(searchTerm);
        const matchStatus = statusFilter === 'ALL' || c.status === statusFilter;
        const matchJob = jobFilter === 'ALL' || (c.job_category_id ? c.job_category_id.toString() === jobFilter : jobFilter === 'UNASSIGNED');
        return matchSearch && matchStatus && matchJob;
    });

    const uniqueStatuses = [...new Set(candidates.map(c => c.status).filter(Boolean))];

    if (loading) return <div style={{ padding: '3rem', textAlign: 'center', color: 'rgba(45,34,28,0.5)' }}>Loading Candidates...</div>;

    return (
        <div style={{ padding: '3rem', margin: '0 auto', display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden' }}>
            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', borderBottom: '2px solid rgba(45, 34, 28, 0.1)', paddingBottom: '1rem', marginBottom: '1.5rem', flexShrink: 0 }}>
                <div>
                    <h1 className="step-title" style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>履歷總管</h1>
                    <p className="step-desc" style={{ margin: 0 }}>管理所有求職者的履歷資料與應徵紀錄。</p>
                </div>
            </div>

            {/* Filters & Search */}
            <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem', flexShrink: 0 }}>
                <div style={{ position: 'relative', flex: 1, maxWidth: '400px' }}>
                    <Search size={18} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'rgba(45,34,28,0.4)' }} />
                    <input
                        type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                        placeholder="搜尋姓名、Email、或電話..." className="form-input" style={{ paddingLeft: '2.5rem', margin: 0 }}
                    />
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Filter size={18} color="rgba(45,34,28,0.5)" />
                    <select className="form-input" style={{ margin: 0, minWidth: '150px' }} value={jobFilter} onChange={e => setJobFilter(e.target.value)}>
                        <option value="ALL">所有職缺</option>
                        <option value="UNASSIGNED">未指派職缺</option>
                        {categories.map(cat => (<option key={cat.id} value={cat.id}>{cat.department} - {cat.position}</option>))}
                    </select>
                    <select className="form-input" style={{ margin: 0, minWidth: '150px' }} value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
                        <option value="ALL">所有狀態</option>
                        {uniqueStatuses.map(status => (<option key={status} value={status}>{status}</option>))}
                    </select>
                </div>
            </div>

            {/* List */}
            <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '0.8rem', paddingRight: '1rem' }}>
                {error && <div style={{ color: 'var(--color-error)', background: 'rgba(224, 49, 49, 0.1)', padding: '1rem', borderRadius: '4px' }}>{error}</div>}

                {filteredCandidates.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '4rem', color: 'rgba(45,34,28,0.4)', background: 'var(--bg-card)', borderRadius: '8px' }}>
                        找不到符合條件的履歷。
                    </div>
                ) : (
                    filteredCandidates.map(candidate => {
                        let resultScores = null;
                        try { resultScores = candidate.result_scores ? JSON.parse(candidate.result_scores) : null; } catch (e) { }
                        const hasTests = !!resultScores;

                        return (
                            <div key={candidate.id}
                                onClick={() => navigate(`/admin/candidates/${candidate.id}`)}
                                style={{
                                    background: 'var(--bg-card)', border: '1px solid var(--border-structural)', borderRadius: '12px',
                                    padding: '1.2rem 1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                                    cursor: 'pointer', transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)', boxShadow: '0 2px 8px rgba(0,0,0,0.02)'
                                }}
                                onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = '0 8px 16px rgba(14, 165, 233, 0.12)'; e.currentTarget.style.borderColor = 'var(--color-accent-blue)'; }}
                                onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.02)'; e.currentTarget.style.borderColor = 'var(--border-structural)'; }}
                            >
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1.5rem', flex: 1 }}>
                                    <div style={{ width: '50px', height: '50px', borderRadius: '50%', background: 'rgba(228, 179, 89, 0.2)', color: 'var(--color-primary)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.5rem', fontWeight: 'bold' }}>
                                        {candidate.name?.charAt(0) || <UserCircle size={28} />}
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.4rem' }}>
                                            <h3 style={{ margin: 0, fontSize: '1.2rem', color: 'var(--color-structural)', fontFamily: 'var(--font-heading)' }}>{candidate.name}</h3>
                                            <span style={{ background: 'rgba(45,34,28,0.05)', padding: '2px 8px', borderRadius: '4px', fontSize: '0.8rem', color: 'rgba(45,34,28,0.7)', fontWeight: 'bold' }}>
                                                {candidate.status || 'Pending'}
                                            </span>
                                        </div>
                                        <div style={{ display: 'flex', gap: '1.5rem', color: 'rgba(45,34,28,0.6)', fontSize: '0.85rem' }}>
                                            <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Briefcase size={14} /> {getJobName(candidate.job_category_id)}</span>
                                            <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}><Calendar size={14} /> {new Date(candidate.created_at).toLocaleDateString()}</span>
                                            {hasTests && <span style={{ color: 'var(--color-primary)', display: 'flex', alignItems: 'center', gap: '4px' }}>✨ 測驗已完成</span>}
                                        </div>
                                    </div>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                    <button
                                        onClick={(e) => handleDeleteCandidate(e, candidate.id, candidate.name)}
                                        title="刪除此履歷"
                                        style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 12px', border: '1px solid rgba(220,38,38,0.3)', borderRadius: '6px', background: 'rgba(220,38,38,0.05)', color: '#dc2626', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 'bold', transition: 'all 0.15s' }}
                                        onMouseEnter={e => { e.currentTarget.style.background = 'rgba(220,38,38,0.12)'; e.currentTarget.style.borderColor = 'rgba(220,38,38,0.5)'; }}
                                        onMouseLeave={e => { e.currentTarget.style.background = 'rgba(220,38,38,0.05)'; e.currentTarget.style.borderColor = 'rgba(220,38,38,0.3)'; }}
                                    >
                                        <Trash2 size={14} /> 刪除
                                    </button>
                                    <div style={{ color: 'var(--color-primary)' }}>
                                        <ChevronRight size={24} />
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

export default ResumeManagement;

import React, { useState, useEffect } from 'react';
import { useForm, useFieldArray, Controller } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import { ChevronRight, ChevronLeft, Plus, Check, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import clsx from 'clsx';
import * as yup from 'yup';

// Validation schema for different steps
const step1Schema = yup.object().shape({
    name: yup.string().required('姓名為必填'),
    job_category_id: yup.string().required('應徵部門/職務為必選'),
    phone: yup.string().required('聯絡方式為必填'),
    rocYear: yup.string().required('民國年為必填'),
    rocMonth: yup.string().required('月為必填'),
    rocDay: yup.string().required('日為必填'),
    education_school: yup.string().required('學校為必填'),
    education_major: yup.string().required('科系為必填'),
    current_salary_monthly: yup.string().required('目前月薪為必填'),
    current_salary_annual: yup.string().required('目前年薪為必填'),
    expected_salary_monthly: yup.string().required('期望月薪為必填'),
    expected_salary_annual: yup.string().required('期望年薪為必填'),
    driving_license: yup.string().required('駕照為必選'),
});

const step2Schema = yup.object().shape({
    work_experiences: yup.array().of(
        yup.object().shape({
            job_title: yup.string().when('$index', (index, schema) => {
                return index === 0 ? schema.required('首筆工作職務為必填') : schema;
            }),
            years: yup.string().when('$index', (index, schema) => {
                return index === 0 ? schema.required('首筆年資為必填') : schema;
            }),
            achievements: yup.string().when('$index', (index, schema) => {
                return index === 0 ? schema.required('首筆工作成果為必填') : schema;
            })
        })
    )
});

const step3Schema = yup.object().shape({
    certifications: yup.string(),
    skills: yup.string(),
    leave_reason: yup.string().required('前份工作離職原因為必填'),
    motivation: yup.string().required('應徵動機為必填')
});

const step4Schema = yup.object().shape({
    career_plan_short: yup.string().required('短期規劃為必填'),
    career_plan_mid: yup.string().required('中期規劃為必填'),
    career_plan_long: yup.string().required('長期規劃為必填'),
    dream: yup.string().required('夢想為必填')
});

const localSteps = [
    { id: 1, title: '應徵資訊', desc: '您的基本聯絡與過往學經歷' },
    { id: 2, title: '工作經歷', desc: '過往的成就與專案經驗' },
    { id: 3, title: '專業與發展', desc: '證照、技能與應徵動機' },
    { id: 4, title: '職涯與夢想', desc: '未來的成長藍圖' }
];

const BasicInfo = () => {
    const navigate = useNavigate();
    const [currentStep, setCurrentStep] = useState(1);
    const [direction, setDirection] = useState(1);
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        const fetchCategories = async () => {
            try {
                const res = await fetch('http://localhost:3001/api/v1/categories');
                const data = await res.json();
                setCategories(data.data || []);
            } catch (err) {
                console.error("Failed to fetch categories", err);
            }
        };
        fetchCategories();
    }, []);

    const getValidationSchema = (step) => {
        switch (step) {
            case 1: return step1Schema;
            case 2: return step2Schema;
            case 3: return step3Schema;
            case 4: return step4Schema;
            default: return step1Schema;
        }
    };

    const { register, control, handleSubmit, trigger, watch, formState: { errors, isSubmitting } } = useForm({
        mode: 'onTouched',
        resolver: async (data, context, options) => {
            try {
                const schema = getValidationSchema(currentStep);
                if (currentStep === 2 && data.work_experiences) {
                    for (let i = 0; i < data.work_experiences.length; i++) {
                        if (i === 0) {
                            if (!data.work_experiences[i].job_title) throw new yup.ValidationError("必填", null, "work_experiences[0].job_title");
                            if (!data.work_experiences[i].years) throw new yup.ValidationError("必填", null, "work_experiences[0].years");
                            if (!data.work_experiences[i].achievements) throw new yup.ValidationError("必填", null, "work_experiences[0].achievements");
                        }
                    }
                } else {
                    await schema.validate(data, { abortEarly: false });
                }
                return { values: data, errors: {} };
            } catch (e) {
                if (e.inner) {
                    return {
                        values: {},
                        errors: e.inner.reduce((acc, curr) => ({ ...acc, [curr.path]: { message: curr.message } }), {})
                    };
                }
                return { values: {}, errors: { [e.path]: { message: e.message } } };
            }
        },
        defaultValues: {
            work_experiences: [{ job_title: '', years: '', achievements: '' }]
        }
    });

    const { fields, append, remove } = useFieldArray({
        control,
        name: "work_experiences"
    });

    // Watch ROC Date for day calculation
    const rocMonth = watch("rocMonth");
    const rocYear = watch("rocYear");
    const [daysInMonth, setDaysInMonth] = useState(31);

    useEffect(() => {
        if (rocMonth && rocYear) {
            // Calculate leap year for ROC (West Year = ROC + 1911)
            const year = parseInt(rocYear) + 1911;
            const month = parseInt(rocMonth);
            const days = new Date(year, month, 0).getDate();
            setDaysInMonth(days);
        }
    }, [rocMonth, rocYear]);

    const nextStep = async () => {
        const isStepValid = await trigger();
        if (isStepValid) {
            setDirection(1);
            setCurrentStep(prev => Math.min(prev + 1, 4));
        }
    };

    const prevStep = () => {
        setDirection(-1);
        setCurrentStep(prev => Math.max(prev - 1, 1));
    };

    const onSubmit = async (data) => {
        if (currentStep !== 4) return;
        try {
            // Combine ROC date
            data.birth_date = `民國${data.rocYear}年${data.rocMonth}月${data.rocDay}日`;

            const response = await fetch('http://localhost:3001/api/v1/candidates', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            });
            if (response.ok) {
                const result = await response.json();
                sessionStorage.setItem('candidateId', result.id);
                navigate('/qa');
            }
        } catch (error) {
            console.error('Submission error', error);
        }
    };

    const pageVariants = {
        initial: (direction) => ({ x: direction > 0 ? 30 : -30, opacity: 0 }),
        in: { x: 0, opacity: 1 },
        out: (direction) => ({ x: direction < 0 ? 30 : -30, opacity: 0 })
    };

    return (
        <div style={{ width: '100%', display: 'flex', justifyContent: 'center' }}>
            <div className="wizard-wrapper">
                {/* Local Sidebar */}
                <aside className="wizard-sidebar">
                    <div className="sidebar-global-progress">
                        <div className="global-step active">
                            <span className="global-step-num">01</span>
                            <span className="global-step-title">基本資料</span>
                        </div>
                        <div className="global-step">
                            <span className="global-step-num">02</span>
                            <span className="global-step-title">專業問答</span>
                        </div>
                        <div className="global-step">
                            <span className="global-step-num">03</span>
                            <span className="global-step-title">性格測驗</span>
                        </div>
                    </div>

                    <div className="local-step-list">
                        {localSteps.map(step => (
                            <div key={step.id} className={clsx("local-step", {
                                'active': currentStep === step.id,
                                'completed': currentStep > step.id
                            })}>
                                {step.title}
                            </div>
                        ))}
                    </div>

                </aside>

                {/* Form Content */}
                <main className="wizard-content">
                    <form onSubmit={handleSubmit(onSubmit)}>

                        <AnimatePresence mode="wait" custom={direction}>
                            <motion.div
                                key={currentStep}
                                custom={direction}
                                variants={pageVariants}
                                initial="initial"
                                animate="in"
                                exit="out"
                                transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                            >

                                {/* Step 1: Application Info */}
                                {currentStep === 1 && (
                                    <div>
                                        <h2 className="step-title">應徵資訊</h2>
                                        <p className="step-desc">請填寫您的基本聯絡方式與學歷</p>

                                        <div className="grid-2">
                                            <div className="form-group">
                                                <label className="form-label required">應徵姓名</label>
                                                <input {...register("name")} className={clsx("form-input", { error: errors.name })} placeholder="真實姓名..." autoComplete="off" />
                                                {errors.name && <span className="error-text">{errors.name.message}</span>}
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label required">應徵部門與職缺</label>
                                                <select {...register("job_category_id")} className={clsx("form-input", { error: errors.job_category_id })}>
                                                    <option value="">請選擇開放面試之職缺</option>
                                                    {categories.map(c => (
                                                        <option key={c.id} value={c.id}>{c.department} - {c.position}</option>
                                                    ))}
                                                </select>
                                                {errors.job_category_id && <span className="error-text">{errors.job_category_id.message}</span>}
                                            </div>
                                        </div>

                                        <div className="grid-2">
                                            <div className="form-group">
                                                <label className="form-label required">聯絡方式 (手機)</label>
                                                <input {...register("phone")} className={clsx("form-input", { error: errors.phone })} placeholder="09XX-XXX-XXX" autoComplete="off" />
                                                {errors.phone && <span className="error-text">{errors.phone.message}</span>}
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label required">出生日期 (民國)</label>
                                                <div className="roc-date-container">
                                                    <div style={{ flex: 1 }}>
                                                        <select {...register("rocYear")} className={clsx("form-input", { error: errors.rocYear })}>
                                                            <option value="">年</option>
                                                            {Array.from({ length: 61 }, (_, i) => 110 - i).map(year => (
                                                                <option key={year} value={year}>{year}</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                    <div style={{ flex: 1 }}>
                                                        <select {...register("rocMonth")} className={clsx("form-input", { error: errors.rocMonth })}>
                                                            <option value="">月</option>
                                                            {Array.from({ length: 12 }, (_, i) => i + 1).map(month => (
                                                                <option key={month} value={month.toString().padStart(2, '0')}>{month}</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                    <div style={{ flex: 1 }}>
                                                        <select {...register("rocDay")} className={clsx("form-input", { error: errors.rocDay })}>
                                                            <option value="">日</option>
                                                            {Array.from({ length: daysInMonth }, (_, i) => i + 1).map(day => (
                                                                <option key={day} value={day.toString().padStart(2, '0')}>{day}</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                </div>
                                                {(errors.rocYear || errors.rocMonth || errors.rocDay) &&
                                                    <span className="error-text">請完整選擇出生年月日</span>}
                                            </div>
                                        </div>

                                        <div className="grid-2">
                                            <div className="form-group">
                                                <label className="form-label required">學校</label>
                                                <input {...register("education_school")} className={clsx("form-input", { error: errors.education_school })} placeholder="最高學歷學校名稱" autoComplete="off" />
                                                {errors.education_school && <span className="error-text">{errors.education_school.message}</span>}
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label required">科系</label>
                                                <input {...register("education_major")} className={clsx("form-input", { error: errors.education_major })} placeholder="就讀科系與學位" autoComplete="off" />
                                                {errors.education_major && <span className="error-text">{errors.education_major.message}</span>}
                                            </div>
                                        </div>

                                        <div className="grid-2">
                                            <div className="form-group">
                                                <label className="form-label required">目前薪資 (月薪)</label>
                                                <input {...register("current_salary_monthly")} className={clsx("form-input", { error: errors.current_salary_monthly })} placeholder="TWD" autoComplete="off" />
                                                {errors.current_salary_monthly && <span className="error-text">{errors.current_salary_monthly.message}</span>}
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label required">目前薪資 (年薪)</label>
                                                <input {...register("current_salary_annual")} className={clsx("form-input", { error: errors.current_salary_annual })} placeholder="TWD" autoComplete="off" />
                                                {errors.current_salary_annual && <span className="error-text">{errors.current_salary_annual.message}</span>}
                                            </div>
                                        </div>

                                        <div className="grid-2">
                                            <div className="form-group">
                                                <label className="form-label required">期望薪資 (月薪)</label>
                                                <input {...register("expected_salary_monthly")} className={clsx("form-input", { error: errors.expected_salary_monthly })} placeholder="TWD" autoComplete="off" />
                                                {errors.expected_salary_monthly && <span className="error-text">{errors.expected_salary_monthly.message}</span>}
                                            </div>
                                            <div className="form-group">
                                                <label className="form-label required">期望薪資 (年薪)</label>
                                                <input {...register("expected_salary_annual")} className={clsx("form-input", { error: errors.expected_salary_annual })} placeholder="TWD" autoComplete="off" />
                                                {errors.expected_salary_annual && <span className="error-text">{errors.expected_salary_annual.message}</span>}
                                            </div>
                                        </div>

                                        <div className="form-group" style={{ maxWidth: '50%' }}>
                                            <label className="form-label required">駕照</label>
                                            <select {...register("driving_license")} className={clsx("form-input", { error: errors.driving_license })}>
                                                <option value="">請選擇</option>
                                                <option value="none">無</option>
                                                <option value="motorcycle">機車</option>
                                                <option value="car">汽車</option>
                                                <option value="both">皆有</option>
                                            </select>
                                            {errors.driving_license && <span className="error-text">{errors.driving_license.message}</span>}
                                        </div>
                                    </div>
                                )}

                                {/* Step 2: Work Experience */}
                                {currentStep === 2 && (
                                    <div>
                                        <h2 className="step-title">工作經歷</h2>
                                        <p className="step-desc">首筆經歷為必填，請專注於「量化成就」展現自己的價值。</p>

                                        {fields.map((item, index) => (
                                            <div key={item.id} className="repeater-card">
                                                <h4 style={{ marginBottom: '1.5rem', color: 'rgba(24,24,27,0.6)' }}>
                                                    {index === 0 ? '最近一份工作' : `第 ${index + 1} 份工作經驗 (選填)`}
                                                </h4>

                                                <div className="grid-2">
                                                    <div className="form-group" style={{ marginBottom: '1.5rem' }}>
                                                        <label className={clsx("form-label", { required: index === 0 })}>公司與職務</label>
                                                        <input
                                                            {...register(`work_experiences.${index}.job_title`)}
                                                            className={clsx("form-input", { error: errors.work_experiences?.[index]?.job_title })}
                                                            placeholder="公司名稱 - 職稱職位"
                                                        />
                                                        {errors.work_experiences?.[index]?.job_title && <span className="error-text">{errors.work_experiences[index].job_title.message}</span>}
                                                    </div>
                                                    <div className="form-group" style={{ marginBottom: '1.5rem' }}>
                                                        <label className={clsx("form-label", { required: index === 0 })}>年資</label>
                                                        <input
                                                            {...register(`work_experiences.${index}.years`)}
                                                            className={clsx("form-input", { error: errors.work_experiences?.[index]?.years })}
                                                            placeholder="X年X個月"
                                                        />
                                                        {errors.work_experiences?.[index]?.years && <span className="error-text">{errors.work_experiences[index].years.message}</span>}
                                                    </div>
                                                </div>
                                                <div className="form-group" style={{ marginBottom: '1rem' }}>
                                                    <label className={clsx("form-label", { required: index === 0 })}>工作成果 (請量化敘述)</label>
                                                    <textarea
                                                        {...register(`work_experiences.${index}.achievements`)}
                                                        className={clsx("form-input", { error: errors.work_experiences?.[index]?.achievements })}
                                                        rows="2"
                                                        placeholder="如: 提升轉換率達 20%..."
                                                    />
                                                    {errors.work_experiences?.[index]?.achievements && <span className="error-text">{errors.work_experiences[index].achievements.message}</span>}
                                                </div>

                                                {index > 0 && (
                                                    <div style={{ textAlign: 'right' }}>
                                                        <button type="button" onClick={() => remove(index)} className="btn-secondary" style={{ color: 'var(--color-error)', borderColor: 'transparent', padding: '0.4rem 0.8rem' }}>
                                                            移除此經歷
                                                        </button>
                                                    </div>
                                                )}
                                            </div>
                                        ))}

                                        <button type="button" onClick={() => append({ job_title: '', years: '', achievements: '' })} className="btn-secondary" style={{ marginTop: '0.5rem' }}>
                                            <Plus size={18} /> 新增過往經歷
                                        </button>
                                    </div>
                                )}

                                {/* Step 3: Professional & Motivation */}
                                {currentStep === 3 && (
                                    <div>
                                        <h2 className="step-title">專業與發展</h2>
                                        <p className="step-desc">讓我們更了解您的軟硬實力與加入動機。</p>

                                        <div className="form-group">
                                            <label className="form-label">證照 (選填)</label>
                                            <input {...register("certifications")} className="form-input" placeholder="相關領域證照、外語檢定..." />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label">專業技能 (選填)</label>
                                            <input {...register("skills")} className="form-input" placeholder="程式語言、設計軟體、特定框架..." />
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label required">前份工作離職原因</label>
                                            <textarea {...register("leave_reason")} className={clsx("form-input", { error: errors.leave_reason })} rows="2" placeholder="..." />
                                            {errors.leave_reason && <span className="error-text">{errors.leave_reason.message}</span>}
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label required">應徵動機</label>
                                            <textarea {...register("motivation")} className={clsx("form-input", { error: errors.motivation })} rows="2" placeholder="吸引您投遞的原因為何？" />
                                            {errors.motivation && <span className="error-text">{errors.motivation.message}</span>}
                                        </div>
                                    </div>
                                )}

                                {/* Step 4: Career Planning & Dream */}
                                {currentStep === 4 && (
                                    <div>
                                        <h2 className="step-title">職涯與夢想</h2>
                                        <p className="step-desc">了解您的長期目標，我們希望能與您共同成長。</p>

                                        <div className="form-group">
                                            <label className="form-label required">短期規劃 (1-2年)</label>
                                            <textarea {...register("career_plan_short")} className={clsx("form-input", { error: errors.career_plan_short })} rows="2" />
                                            {errors.career_plan_short && <span className="error-text">{errors.career_plan_short.message}</span>}
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label required">中期規劃 (3-5年)</label>
                                            <textarea {...register("career_plan_mid")} className={clsx("form-input", { error: errors.career_plan_mid })} rows="2" />
                                            {errors.career_plan_mid && <span className="error-text">{errors.career_plan_mid.message}</span>}
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label required">長期規劃 (5年以上)</label>
                                            <textarea {...register("career_plan_long")} className={clsx("form-input", { error: errors.career_plan_long })} rows="2" />
                                            {errors.career_plan_long && <span className="error-text">{errors.career_plan_long.message}</span>}
                                        </div>

                                        <div className="form-group">
                                            <label className="form-label required">人生夢想 (不限於工作)</label>
                                            <textarea {...register("dream")} className={clsx("form-input", { error: errors.dream })} rows="3" placeholder="買島？壯遊？說說你想做什麼！" />
                                            {errors.dream && <span className="error-text">{errors.dream.message}</span>}
                                        </div>
                                    </div>
                                )}
                            </motion.div>
                        </AnimatePresence>

                        {/* Navigation */}
                        <div className="wizard-nav">
                            {currentStep > 1 ? (
                                <button type="button" onClick={prevStep} className="btn-wizard btn-wizard-prev">
                                    上一步
                                </button>
                            ) : <div></div>}

                            {currentStep < 4 ? (
                                <button type="button" onClick={nextStep} className="btn-wizard btn-wizard-next">
                                    繼續 <ArrowRight size={20} />
                                </button>
                            ) : (
                                <button type="submit" disabled={isSubmitting} className="btn-wizard btn-wizard-next">
                                    {isSubmitting ? '處理中...' : '提交基礎資料'}
                                </button>
                            )}
                        </div>
                    </form>
                </main>
            </div>
        </div>
    );
};

export default BasicInfo;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Check } from 'lucide-react';
import clsx from 'clsx';
import { QuestionPicker } from '../utils/colortest_picker';

const PersonalityTest = () => {
    const navigate = useNavigate();
    const candidateId = sessionStorage.getItem('candidateId');

    // Test states
    const [questions, setQuestions] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [answers, setAnswers] = useState([]);
    const [timings, setTimings] = useState([]);
    const [positionSequence, setPositionSequence] = useState([]);

    // Timing states
    const [questionStartTime, setQuestionStartTime] = useState(Date.now());

    // UI states
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState(null);

    useEffect(() => {
        if (!candidateId) {
            navigate('/');
            return;
        }

        // Initialize 30 questions
        const picked = QuestionPicker.pick();
        setQuestions(picked);
        setQuestionStartTime(Date.now());
    }, [candidateId, navigate]);

    const handleOptionClick = (option, optionIndex) => {
        const timeTaken = Math.round((Date.now() - questionStartTime) / 1000);
        const currentQ = questions[currentIndex];

        const newAnswers = [...answers, {
            questionId: currentQ.id,
            color: option.color || null,
            optionText: option.text
        }];

        const newTimings = [...timings, {
            questionId: currentQ.id,
            seconds: timeTaken
        }];

        const newPositionSequence = [...positionSequence, optionIndex];

        // Record answers in state (for rendering, though not strictly needed for final submit)
        setAnswers(newAnswers);
        setTimings(newTimings);
        setPositionSequence(newPositionSequence);

        // Proceed to next or submit
        if (currentIndex < questions.length - 1) {
            setCurrentIndex(prev => prev + 1);
            setQuestionStartTime(Date.now());
        } else {
            submitPersonalityTest(newAnswers, newTimings, newPositionSequence);
        }
    };

    const submitPersonalityTest = async (finalAnswers, finalTimings, finalPositionSequence) => {
        setIsSubmitting(true);
        try {
            // 1. Submit personality test data
            const response = await fetch(`http://localhost:3001/api/v1/candidates/${candidateId}/personality`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    answers: finalAnswers,
                    timings: finalTimings,
                    positionSequence: finalPositionSequence
                })
            });

            if (!response.ok) throw new Error('提交性格測驗失敗');

            // 2. Trigger final submission to mark candidate as 'completed'
            const finalRes = await fetch(`http://localhost:3001/api/v1/candidates/${candidateId}/submit`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' }
            });

            if (!finalRes.ok) throw new Error('最終提交失敗');

            // Clear sessionStorage and navigate to thank you
            sessionStorage.removeItem('qa_draft_' + candidateId);
            sessionStorage.removeItem('candidateId');
            navigate('/thank-you');
        } catch (err) {
            console.error(err);
            setError(err.message);
            setIsSubmitting(false);
        }
    };

    if (questions.length === 0) return null; // Loading state

    const currentQuestion = questions[currentIndex];
    const progressPercentage = ((currentIndex) / 30) * 100;

    return (
        <div style={{ width: '100%', display: 'flex', justifyContent: 'center' }}>
            <div className="wizard-wrapper">
                {/* Global Sidebar layout matching other modules */}
                <aside className="wizard-sidebar">
                    <div className="sidebar-global-progress">
                        <div className="global-step completed">
                            <span className="global-step-num"><Check size={16} /></span>
                            <span className="global-step-title" style={{ opacity: 0.7 }}>基本資料</span>
                        </div>
                        <div className="global-step completed">
                            <span className="global-step-num"><Check size={16} /></span>
                            <span className="global-step-title" style={{ opacity: 0.7 }}>專業問答</span>
                        </div>
                        <div className="global-step active">
                            <span className="global-step-num">03</span>
                            <span className="global-step-title">性格測驗</span>
                        </div>
                    </div>

                    <div className="local-step-list">
                        <div className="local-step active">
                            性格色彩鑑定
                        </div>
                    </div>
                </aside>

                <main className="wizard-content">
                    <div style={{ marginBottom: '3rem' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '1rem' }}>
                            <h2 className="step-title" style={{ fontSize: '1.6rem', marginBottom: 0 }}>
                                問題 {currentIndex + 1}
                            </h2>
                            <span style={{ fontSize: '0.95rem', color: 'var(--color-structural)', fontWeight: '600', opacity: 0.6 }}>
                                進度 {currentIndex + 1} / 30
                            </span>
                        </div>
                        <div style={{ width: '100%', height: '6px', background: 'rgba(0,0,0,0.06)', borderRadius: '3px', overflow: 'hidden' }}>
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${progressPercentage}%` }}
                                style={{ height: '100%', background: 'var(--color-primary)', borderRadius: '3px' }}
                                transition={{ duration: 0.4, ease: "easeInOut" }}
                            />
                        </div>
                    </div>

                    {/* Question Content */}
                    <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                        <AnimatePresence mode="wait">
                            {isSubmitting ? (
                                <motion.div
                                    key="submitting"
                                    initial={{ opacity: 0, scale: 0.95 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    style={{ padding: '4rem 0', textAlign: 'center', margin: 'auto' }}
                                >
                                    <div style={{ display: 'flex', gap: '10px', justifyContent: 'center', marginBottom: '1.5rem' }}>
                                        {['#E4B359', '#4A4233', '#8F2F28', '#2D221C'].map((color, i) => (
                                            <motion.div
                                                key={i}
                                                animate={{ y: [0, -15, 0] }}
                                                transition={{ duration: 0.6, repeat: Infinity, delay: i * 0.15 }}
                                                style={{ width: '15px', height: '15px', borderRadius: '50%', backgroundColor: color }}
                                            />
                                        ))}
                                    </div>
                                    <h2 style={{ fontSize: '1.5rem', color: 'var(--color-primary)', marginBottom: '0.5rem', fontFamily: 'var(--font-heading)' }}>正在透過 AI 分析您的性格色彩...</h2>
                                    <p style={{ color: 'var(--color-structural)', opacity: 0.6 }}>解讀作答模式中，請稍候</p>
                                </motion.div>
                            ) : (
                                <motion.div
                                    key={currentQuestion.id}
                                    initial={{ opacity: 0, x: 20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: -20 }}
                                    transition={{ duration: 0.3 }}
                                    style={{ width: '100%', maxWidth: '800px' }}
                                >
                                    <h3 style={{ fontSize: '1.35rem', lineHeight: '1.6', marginBottom: '2.5rem', color: 'var(--color-structural)', fontWeight: '600' }}>
                                        {currentQuestion.text}
                                    </h3>

                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.2rem' }}>
                                        {currentQuestion.options.map((opt, idx) => (
                                            <button
                                                key={idx}
                                                onClick={() => handleOptionClick(opt, idx)}
                                                className="form-input"
                                                style={{
                                                    textAlign: 'left',
                                                    cursor: 'pointer',
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    padding: '1.2rem 1.5rem',
                                                    height: 'auto',
                                                    whiteSpace: 'normal',
                                                    backgroundColor: 'transparent'
                                                }}
                                                onMouseOver={(e) => {
                                                    e.currentTarget.style.borderColor = 'var(--color-primary)';
                                                    e.currentTarget.style.boxShadow = '4px 4px 0px var(--color-primary)';
                                                    e.currentTarget.style.transform = 'translate(-2px, -2px)';
                                                }}
                                                onMouseOut={(e) => {
                                                    e.currentTarget.style.borderColor = 'var(--border-structural)';
                                                    e.currentTarget.style.boxShadow = 'none';
                                                    e.currentTarget.style.transform = 'translate(0, 0)';
                                                }}
                                            >
                                                <span style={{
                                                    fontFamily: 'var(--font-tech)',
                                                    color: 'var(--color-primary)',
                                                    fontWeight: '700',
                                                    marginRight: '1rem',
                                                    fontSize: '1.1rem'
                                                }}>
                                                    {opt.letter}.
                                                </span>
                                                <span style={{ fontSize: '1.1rem' }}>{opt.text}</span>
                                            </button>
                                        ))}
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    {error && (
                        <div style={{ color: 'var(--error-color)', marginTop: '2rem', padding: '1rem', background: 'rgba(143, 47, 40, 0.1)', borderRadius: '8px', textAlign: 'center' }}>
                            {error}
                        </div>
                    )}
                </main>
            </div>
        </div>
    );
};

export default PersonalityTest;

