import React, { useState, useEffect, useRef } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import { ChevronRight, ChevronLeft, ArrowRight, Check } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import clsx from 'clsx';
import questionsData from '../data/questions.json';

const QA = () => {
    const navigate = useNavigate();
    const [currentStep, setCurrentStep] = useState(1);
    const [direction, setDirection] = useState(1);
    const contentRef = useRef(null);

    // Check if user came from Basic Info
    const candidateId = sessionStorage.getItem('candidateId');

    const { register, handleSubmit, watch, reset, formState: { errors } } = useForm();

    // Auto-save draft
    const formValues = watch();

    useEffect(() => {
        if (!candidateId) {
            alert('請先填寫基本資料！');
            navigate('/');
            return;
        }

        // Load draft if exists
        const draft = sessionStorage.getItem(`qa_draft_${candidateId}`);
        if (draft) {
            try {
                reset(JSON.parse(draft));
            } catch (e) {
                console.error("Failed to load draft");
            }
        }
    }, [candidateId, navigate, reset]);

    useEffect(() => {
        if (candidateId && Object.keys(formValues).length > 0) {
            sessionStorage.setItem(`qa_draft_${candidateId}`, JSON.stringify(formValues));
        }
    }, [formValues, candidateId]);

    // Scroll to top when step changes
    useEffect(() => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
        if (contentRef.current) {
            contentRef.current.scrollTo({ top: 0, behavior: 'smooth' });
        }
    }, [currentStep]);

    const nextStep = () => {
        setDirection(1);
        setCurrentStep(prev => Math.min(prev + 1, 6));
    };

    const prevStep = () => {
        setDirection(-1);
        setCurrentStep(prev => Math.max(prev - 1, 1));
    };

    const onSubmit = async (data) => {
        if (currentStep !== 6) return;

        try {
            // Transform data object to array of { question_code, answer_text }
            const formattedAnswers = Object.keys(data).map(key => ({
                question_code: key,
                answer_text: data[key]
            })).filter(ans => ans.answer_text); // Only send filled answers

            const response = await fetch(`http://localhost:3001/api/v1/candidates/${candidateId}/answers`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ answers: formattedAnswers })
            });

            if (response.ok) {
                // Clear draft on successful submission
                sessionStorage.removeItem(`qa_draft_${candidateId}`);
                console.log('QA Answers Submitted successfully');
                navigate('/personality');
            } else {
                console.error('Failed to submit answers');
                alert('提交失敗，請重試');
            }
        } catch (error) {
            console.error('Error submitting answers:', error);
            alert('系統發生錯誤，請稍後再試');
        }
    };

    return (
        <div style={{ width: '100%', display: 'flex', justifyContent: 'center' }}>
            <div className="wizard-wrapper">
                {/* Local Sidebar */}
                <aside className="wizard-sidebar">
                    <div className="sidebar-global-progress">
                        <div className="global-step completed">
                            <span className="global-step-num"><Check size={16} /></span>
                            <span className="global-step-title" style={{ opacity: 0.7 }}>基本資料</span>
                        </div>
                        <div className="global-step active">
                            <span className="global-step-num">02</span>
                            <span className="global-step-title">專業問答</span>
                        </div>
                        <div className="global-step">
                            <span className="global-step-num">03</span>
                            <span className="global-step-title">性格測驗</span>
                        </div>
                    </div>

                    <div className="local-step-list">
                        {questionsData.map(step => (
                            <div key={step.category_id} className={clsx("local-step", {
                                'active': currentStep === step.category_id,
                                'completed': currentStep > step.category_id
                            })}>
                                {step.category}
                            </div>
                        ))}
                    </div>
                </aside>

                <main className="wizard-content" ref={contentRef}>
                    <form onSubmit={handleSubmit(onSubmit)}>
                        <h2 className="step-title">{questionsData[currentStep - 1].category}</h2>
                        <p className="step-desc">此大題共有 {questionsData[currentStep - 1].questions.length} 題，請盡可能詳細地描述您的經驗與想法。</p>

                        <div className="qa-questions-container">
                            <AnimatePresence mode="wait">
                                <motion.div
                                    key={currentStep}
                                    initial={{ x: direction * 20, opacity: 0 }}
                                    animate={{ x: 0, opacity: 1 }}
                                    exit={{ x: -direction * 20, opacity: 0 }}
                                    transition={{ duration: 0.3 }}
                                >
                                    {questionsData[currentStep - 1].questions.map((q, index) => (
                                        <div key={q.id} className="form-group" style={{ marginBottom: '2.5rem' }}>
                                            <label className="form-label" style={{ fontSize: '1.05rem', lineHeight: '1.6', marginBottom: '1rem', color: 'var(--text-primary)' }}>
                                                <span style={{ color: 'var(--color-primary)', fontWeight: 'bold', marginRight: '8px' }}>
                                                    {index + 1}.
                                                </span>
                                                {q.text}
                                            </label>
                                            <textarea
                                                {...register(q.id)}
                                                className="form-input"
                                                rows="4"
                                                placeholder="請在此輸入您的回答..."
                                                style={{ resize: 'vertical', minHeight: '100px' }}
                                            />
                                        </div>
                                    ))}
                                </motion.div>
                            </AnimatePresence>
                        </div>

                        {/* Navigation */}
                        <div className="wizard-nav">
                            {currentStep > 1 ? (
                                <button type="button" onClick={prevStep} className="btn-wizard btn-wizard-prev">
                                    上一類
                                </button>
                            ) : <div></div>}

                            {currentStep < 6 ? (
                                <button type="button" onClick={nextStep} className="btn-wizard btn-wizard-next">
                                    下一類 <ArrowRight size={20} />
                                </button>
                            ) : (
                                <button type="submit" className="btn-wizard btn-wizard-next">
                                    完成問答 <ArrowRight size={20} />
                                </button>
                            )}
                        </div>
                    </form>
                </main>
            </div>
        </div>
    );
};

export default QA;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { CheckCircle, Home, ShieldCheck } from 'lucide-react';

const ThankYou = () => {
    const navigate = useNavigate();
    const [countdown, setCountdown] = useState(30); // Use 30 seconds instead of 10s based on user feedback

    useEffect(() => {
        // Clear all session storage on landing here to reset for the next candidate
        sessionStorage.clear();

        const timer = setInterval(() => {
            setCountdown((prev) => {
                if (prev <= 1) {
                    clearInterval(timer);
                    navigate('/');
                    return 0;
                }
                return prev - 1;
            });
        }, 1000);

        return () => clearInterval(timer);
    }, [navigate]);

    return (
        <div style={{
            width: '100%',
            minHeight: '80vh',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            padding: '2rem'
        }}>
            <motion.div
                initial={{ opacity: 0, scale: 0.95, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="glass-card p-xl"
                style={{
                    maxWidth: '600px',
                    width: '100%',
                    textAlign: 'center',
                    padding: '4rem 3rem'
                }}
            >
                <div style={{ marginBottom: '2rem' }}>
                    <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        transition={{ delay: 0.3, type: "spring", stiffness: 200 }}
                        style={{
                            width: '80px',
                            height: '80px',
                            borderRadius: '50%',
                            background: 'var(--color-primary)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            margin: '0 auto',
                            boxShadow: '0 0 30px rgba(228, 179, 89, 0.4)'
                        }}
                    >
                        <CheckCircle size={40} color="var(--color-structural)" strokeWidth={2.5} />
                    </motion.div>
                </div>

                <h2 style={{ fontSize: '2rem', fontFamily: 'var(--font-heading)', color: 'var(--color-structural)', marginBottom: '1rem' }}>
                    感謝您的填寫！
                </h2>

                <p style={{ fontSize: '1.1rem', color: 'var(--color-structural)', opacity: 0.8, marginBottom: '2rem', lineHeight: '1.6' }}>
                    您的面試資料（包含基本資料、專業問答與性格測驗）已完整且安全地儲存至加密伺服器後台。<br />
                    人資團隊將會盡快與您聯繫後續事宜。
                </p>

                <div style={{
                    background: 'rgba(255,255,255,0.5)',
                    border: '1px solid var(--border-structural)',
                    padding: '1rem',
                    borderRadius: '12px',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '10px',
                    marginBottom: '3rem'
                }}>
                    <ShieldCheck size={20} color="var(--color-primary)" />
                    <span style={{ fontSize: '0.9rem', color: 'var(--color-structural)', fontWeight: '500' }}>資料已自動安全歸檔完畢</span>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.5rem' }}>
                    <button
                        onClick={() => navigate('/')}
                        className="btn-wizard btn-wizard-next"
                        style={{ padding: '1rem 2.5rem', width: 'auto' }}
                    >
                        <Home size={20} /> 返回首頁
                    </button>
                    <span style={{ fontSize: '0.9rem', fontFamily: 'var(--font-tech)', color: 'var(--color-structural)', opacity: 0.5 }}>
                        系統將在 {countdown} 秒後自動為您清理畫面並返回首頁
                    </span>
                </div>
            </motion.div>
        </div>
    );
};

export default ThankYou;

